pragma solidity ^0.5.12;

import "./ERC721.sol";
import "./ERC721Enumerable.sol";
import "./ERC721Metadata.sol";


interface AsyncArtwork_v1 {
    function getControlToken(uint256 controlTokenId) external view returns (int256[] memory);

    function tokenURI(uint256 tokenId) external view returns (string memory);
}





contract AsyncArtwork_v2 is Initializable, ERC721, ERC721Enumerable, ERC721Metadata {

    event PlatformAddressUpdated(
        address platformAddress
    );

    event PermissionUpdated(
        uint256 tokenId,
        address tokenOwner,
        address permissioned
    );


    event CreatorWhitelisted(
        uint256 tokenId,
        uint256 layerCount,
        address creator
    );


    event PlatformSalePercentageUpdated (
        uint256 tokenId,
        uint256 platformFirstPercentage,
        uint256 platformSecondPercentage        
    );


    event ArtistSecondSalePercentUpdated (
        uint256 artistSecondPercentage
    );


    event BidProposed(
        uint256 tokenId,
        uint256 bidAmount,
        address bidder
    );


    event BidWithdrawn(
        uint256 tokenId
    );


    event BuyPriceSet(
        uint256 tokenId,
        uint256 price
    );


    event TokenSale(

        uint256 tokenId,

        uint256 salePrice,

        address buyer
    );


    event ControlLeverUpdated(

        uint256 tokenId,

        uint256 priorityTip,

        int256 numRemainingUpdates,

        uint256[] leverIds,        

        int256[] previousValues,

        int256[] updatedValues
    );


    struct ControlToken {

        uint256 numControlLevers;

        int256 numRemainingUpdates;

        bool exists;

        bool isSetup;

        mapping(uint256 => ControlLever) levers;
    }


    struct ControlLever {

        int256 minValue;

        int256 maxValue;

        int256 currentValue;

        bool exists;
    }


    struct PendingBid {

        address payable bidder;

        uint256 amount;

        bool exists;
    }

    struct WhitelistReservation {

        address creator;

        uint256 layerCount;
    }


    mapping(uint256 => bool) public tokenDidHaveFirstSale;

    mapping(uint256 => bool) public tokenURILocked;    

    mapping(uint256 => uint256) public buyPrices;    

    mapping(address => uint256) public failedTransferCredits;

    mapping(uint256 => uint256) public platformFirstSalePercentages;

    mapping(uint256 => uint256) public platformSecondSalePercentages;

    mapping(uint256 => WhitelistReservation) public creatorWhitelist;

    mapping(uint256 => address payable[]) public uniqueTokenCreators;    

    mapping(uint256 => PendingBid) public pendingBids;


    mapping(uint256 => ControlToken) controlTokenMapping;    

    mapping(address => mapping(uint256 => address)) public permissionedControllers;

    uint256 public artistSecondSalePercentage;

    uint256 public expectedTokenSupply;

    uint256 public minBidIncreasePercent;

    address payable public platformAddress;

    address public upgraderAddress;

    function initialize(string memory name, string memory symbol, uint256 initialExpectedTokenSupply, address _upgraderAddress) public initializer {
        ERC721.initialize();
        ERC721Enumerable.initialize();
        ERC721Metadata.initialize(name, symbol);


        artistSecondSalePercentage = 10;


        minBidIncreasePercent = 1;


        platformAddress = msg.sender;


        upgraderAddress = _upgraderAddress;


        expectedTokenSupply = initialExpectedTokenSupply;

        require(expectedTokenSupply > 0);
    }


    modifier onlyPlatform() {
        require(msg.sender == platformAddress);
        _;
    }

    modifier onlyWhitelistedCreator(uint256 masterTokenId, uint256 layerCount) {
        require(creatorWhitelist[masterTokenId].creator == msg.sender);
        require(creatorWhitelist[masterTokenId].layerCount == layerCount);
        _;
    }


    function whitelistTokenForCreator(address creator, uint256 masterTokenId, uint256 layerCount, 
        uint256 platformFirstSalePercentage, uint256 platformSecondSalePercentage) external onlyPlatform {

        require(masterTokenId == expectedTokenSupply);

        require (layerCount > 0);

        creatorWhitelist[masterTokenId] = WhitelistReservation(creator, layerCount);

        expectedTokenSupply = masterTokenId.add(layerCount).add(1);

        platformFirstSalePercentages[masterTokenId] = platformFirstSalePercentage;
        platformSecondSalePercentages[masterTokenId] = platformSecondSalePercentage;

        emit CreatorWhitelisted(masterTokenId, layerCount, creator);
    }


    function updatePlatformAddress(address payable newPlatformAddress) external onlyPlatform {
        platformAddress = newPlatformAddress;

        emit PlatformAddressUpdated(newPlatformAddress);
    }


    function waiveFirstSaleRequirement(uint256 tokenId) external onlyPlatform {

        tokenDidHaveFirstSale[tokenId] = true;
    }


    function updatePlatformSalePercentage(uint256 tokenId, uint256 platformFirstSalePercentage, 
        uint256 platformSecondSalePercentage) external onlyPlatform {

        platformFirstSalePercentages[tokenId] = platformFirstSalePercentage;
        platformSecondSalePercentages[tokenId] = platformSecondSalePercentage;

        emit PlatformSalePercentageUpdated(tokenId, platformFirstSalePercentage, platformSecondSalePercentage);
    }

    function updateMinimumBidIncreasePercent(uint256 _minBidIncreasePercent) external onlyPlatform {
        require((_minBidIncreasePercent > 0) && (_minBidIncreasePercent <= 50), "Bid increases must be within 0-50%");

        minBidIncreasePercent = _minBidIncreasePercent;
    }

    function updateTokenURI(uint256 tokenId, string calldata tokenURI) external onlyPlatform {

        require(_exists(tokenId));

        require(tokenURILocked[tokenId] == false);

        super._setTokenURI(tokenId, tokenURI);
    }


    function lockTokenURI(uint256 tokenId) external onlyPlatform {

        require(_exists(tokenId));

        tokenURILocked[tokenId] = true;
    }


    function updateArtistSecondSalePercentage(uint256 _artistSecondSalePercentage) external onlyPlatform {

        artistSecondSalePercentage = _artistSecondSalePercentage;

        emit ArtistSecondSalePercentUpdated(artistSecondSalePercentage);
    }

    function setupControlToken(uint256 controlTokenId, string calldata controlTokenURI,
        int256[] calldata leverMinValues,
        int256[] calldata leverMaxValues,
        int256[] calldata leverStartValues,
        int256 numAllowedUpdates,
        address payable[] calldata additionalCollaborators
    ) external {

        require (leverMinValues.length <= 500, "Too many control levers.");

        require (additionalCollaborators.length <= 50, "Too many collaborators.");

        require(controlTokenMapping[controlTokenId].exists, "No control token found");

        require(controlTokenMapping[controlTokenId].isSetup == false, "Already setup");

        require(uniqueTokenCreators[controlTokenId][0] == msg.sender, "Must be control token artist");

        require((leverMinValues.length == leverMaxValues.length) && (leverMaxValues.length == leverStartValues.length), "Values array mismatch");

        require((numAllowedUpdates == -1) || (numAllowedUpdates > 0), "Invalid allowed updates");

        super._safeMint(msg.sender, controlTokenId);

        super._setTokenURI(controlTokenId, controlTokenURI);        

        controlTokenMapping[controlTokenId] = ControlToken(leverStartValues.length, numAllowedUpdates, true, true);

        for (uint256 k = 0; k < leverStartValues.length; k++) {

            require(leverMaxValues[k] >= leverMinValues[k], "Max val must >= min");

            require((leverStartValues[k] >= leverMinValues[k]) && (leverStartValues[k] <= leverMaxValues[k]), "Invalid start val");

            controlTokenMapping[controlTokenId].levers[k] = ControlLever(leverMinValues[k],
                leverMaxValues[k], leverStartValues[k], true);
        }

        for (uint256 i = 0; i < additionalCollaborators.length; i++) {

            require(additionalCollaborators[i] != address(0));

            uniqueTokenCreators[controlTokenId].push(additionalCollaborators[i]);
        }
    }


    function upgradeV1Token(uint256 tokenId, address v1Address, bool isControlToken, address to, 
        uint256 platformFirstPercentageForToken, uint256 platformSecondPercentageForToken, bool hasTokenHadFirstSale,
        address payable[] calldata uniqueTokenCreatorsForToken) external {

        AsyncArtwork_v1 v1Token = AsyncArtwork_v1(v1Address);


        require(msg.sender == upgraderAddress, "Only upgrader can call.");


        uniqueTokenCreators[tokenId] = uniqueTokenCreatorsForToken;

        if (isControlToken) {

            int256[] memory controlToken = v1Token.getControlToken(tokenId);

            require(controlToken.length % 3 == 0, "Invalid control token.");

            require(controlToken.length > 0, "Control token must have levers");            


            controlTokenMapping[tokenId] = ControlToken(controlToken.length / 3, -1, true, true);



            for (uint256 k = 0; k < controlToken.length; k+=3) {
                controlTokenMapping[tokenId].levers[k / 3] = ControlLever(controlToken[k],
                    controlToken[k + 1], controlToken[k + 2], true);
            }
        }


        platformFirstSalePercentages[tokenId] = platformFirstPercentageForToken;

        platformSecondSalePercentages[tokenId] = platformSecondPercentageForToken;


        tokenDidHaveFirstSale[tokenId] = hasTokenHadFirstSale;


        super._safeMint(to, tokenId);


        super._setTokenURI(tokenId, v1Token.tokenURI(tokenId));
    }

    function mintArtwork(uint256 masterTokenId, string calldata artworkTokenURI, address payable[] calldata controlTokenArtists)
        external onlyWhitelistedCreator(masterTokenId, controlTokenArtists.length) {

        require(masterTokenId > 0);

        super._safeMint(msg.sender, masterTokenId);

        super._setTokenURI(masterTokenId, artworkTokenURI);

        uniqueTokenCreators[masterTokenId].push(msg.sender);

        for (uint256 i = 0; i < controlTokenArtists.length; i++) {

            require(controlTokenArtists[i] != address(0));

            uint256 controlTokenId = masterTokenId + i + 1;

            uniqueTokenCreators[controlTokenId].push(controlTokenArtists[i]);

            controlTokenMapping[controlTokenId] = ControlToken(0, 0, true, false);


            platformFirstSalePercentages[controlTokenId] = platformFirstSalePercentages[masterTokenId];

            platformSecondSalePercentages[controlTokenId] = platformSecondSalePercentages[masterTokenId];

            if (controlTokenArtists[i] != msg.sender) {
                bool containsControlTokenArtist = false;

                for (uint256 k = 0; k < uniqueTokenCreators[masterTokenId].length; k++) {
                    if (uniqueTokenCreators[masterTokenId][k] == controlTokenArtists[i]) {
                        containsControlTokenArtist = true;
                        break;
                    }
                }
                if (containsControlTokenArtist == false) {
                    uniqueTokenCreators[masterTokenId].push(controlTokenArtists[i]);
                }
            }
        }
    }

    function bid(uint256 tokenId) external payable {

        require(msg.value > 0);

        require(_isApprovedOrOwner(msg.sender, tokenId) == false);

        if (pendingBids[tokenId].exists) {

            require(msg.value >= (pendingBids[tokenId].amount.mul(minBidIncreasePercent.add(100)).div(100)), "Bid must increase by min %");

            safeFundsTransfer(pendingBids[tokenId].bidder, pendingBids[tokenId].amount);
        }

        pendingBids[tokenId] = PendingBid(msg.sender, msg.value, true);

        emit BidProposed(tokenId, msg.value, msg.sender);
    }

    function withdrawBid(uint256 tokenId) external {

        require((pendingBids[tokenId].bidder == msg.sender) || (msg.sender == platformAddress));

        _withdrawBid(tokenId);        
    }
    function _withdrawBid(uint256 tokenId) internal {
        require(pendingBids[tokenId].exists);

        safeFundsTransfer(pendingBids[tokenId].bidder, pendingBids[tokenId].amount);

        pendingBids[tokenId] = PendingBid(address(0), 0, false);

        emit BidWithdrawn(tokenId);
    }



    function takeBuyPrice(uint256 tokenId, int256 expectedRemainingUpdates) external payable {

        require(_isApprovedOrOwner(msg.sender, tokenId) == false);

        uint256 saleAmount = buyPrices[tokenId];

        require(saleAmount > 0);

        require(msg.value == saleAmount);

        if (controlTokenMapping[tokenId].exists) {

            require(controlTokenMapping[tokenId].numRemainingUpdates == expectedRemainingUpdates);
        }

        if (pendingBids[tokenId].exists) {

            safeFundsTransfer(pendingBids[tokenId].bidder, pendingBids[tokenId].amount);

            pendingBids[tokenId] = PendingBid(address(0), 0, false);
        }
        onTokenSold(tokenId, saleAmount, msg.sender);
    }


    function distributeFundsToCreators(uint256 amount, address payable[] memory creators) private {
        uint256 creatorShare = amount.div(creators.length);

        for (uint256 i = 0; i < creators.length; i++) {
            safeFundsTransfer(creators[i], creatorShare);
        }
    }



    function onTokenSold(uint256 tokenId, uint256 saleAmount, address to) private {

        if (tokenDidHaveFirstSale[tokenId]) {

            uint256 platformAmount = saleAmount.mul(platformSecondSalePercentages[tokenId]).div(100);
            safeFundsTransfer(platformAddress, platformAmount);

            uint256 creatorAmount = saleAmount.mul(artistSecondSalePercentage).div(100);
            distributeFundsToCreators(creatorAmount, uniqueTokenCreators[tokenId]);

            address payable payableOwner = address(uint160(ownerOf(tokenId)));

            safeFundsTransfer(payableOwner, saleAmount.sub(platformAmount).sub(creatorAmount));
        } else {
            tokenDidHaveFirstSale[tokenId] = true;

            uint256 platformAmount = saleAmount.mul(platformFirstSalePercentages[tokenId]).div(100);
            safeFundsTransfer(platformAddress, platformAmount);


            distributeFundsToCreators(saleAmount.sub(platformAmount), uniqueTokenCreators[tokenId]);
        }

        pendingBids[tokenId] = PendingBid(address(0), 0, false);

        _transferFrom(ownerOf(tokenId), to, tokenId);

        emit TokenSale(tokenId, saleAmount, to);
    }



    function acceptBid(uint256 tokenId, uint256 minAcceptedAmount) external {

        require(_isApprovedOrOwner(msg.sender, tokenId));

        require(pendingBids[tokenId].exists);

        require(pendingBids[tokenId].amount >= minAcceptedAmount);

        onTokenSold(tokenId, pendingBids[tokenId].amount, pendingBids[tokenId].bidder);
    }


    function makeBuyPrice(uint256 tokenId, uint256 amount) external {

        require(_isApprovedOrOwner(msg.sender, tokenId));

        buyPrices[tokenId] = amount;

        emit BuyPriceSet(tokenId, amount);
    }


    function getNumRemainingControlUpdates(uint256 controlTokenId) external view returns (int256) {
        require(controlTokenMapping[controlTokenId].exists, "Token does not exist.");

        return controlTokenMapping[controlTokenId].numRemainingUpdates;
    }


    function getControlToken(uint256 controlTokenId) external view returns(int256[] memory) {
        require(controlTokenMapping[controlTokenId].exists, "Token does not exist.");

        ControlToken storage controlToken = controlTokenMapping[controlTokenId];

        int256[] memory returnValues = new int256[](controlToken.numControlLevers.mul(3));
        uint256 returnValIndex = 0;


        for (uint256 i = 0; i < controlToken.numControlLevers; i++) {
            returnValues[returnValIndex] = controlToken.levers[i].minValue;
            returnValIndex = returnValIndex.add(1);

            returnValues[returnValIndex] = controlToken.levers[i].maxValue;
            returnValIndex = returnValIndex.add(1);

            returnValues[returnValIndex] = controlToken.levers[i].currentValue;
            returnValIndex = returnValIndex.add(1);
        }

        return returnValues;
    }


    function grantControlPermission(uint256 tokenId, address permissioned) external {
        permissionedControllers[msg.sender][tokenId] = permissioned;

        emit PermissionUpdated(tokenId, msg.sender, permissioned);
    }



    function useControlToken(uint256 controlTokenId, uint256[] calldata leverIds, int256[] calldata newValues) external payable {

        require(_isApprovedOrOwner(msg.sender, controlTokenId) || (permissionedControllers[ownerOf(controlTokenId)][controlTokenId] == msg.sender),
            "Owner or permissioned only");

        require(controlTokenMapping[controlTokenId].exists, "Token does not exist.");

        ControlToken storage controlToken = controlTokenMapping[controlTokenId];

        require((controlToken.numRemainingUpdates == -1) || (controlToken.numRemainingUpdates > 0), "No more updates allowed");        

        int256[] memory previousValues = new int256[](newValues.length);

        for (uint256 i = 0; i < leverIds.length; i++) {

            ControlLever storage lever = controlTokenMapping[controlTokenId].levers[leverIds[i]];


            require((newValues[i] >= lever.minValue) && (newValues[i] <= lever.maxValue), "Invalid val");


            require(newValues[i] != lever.currentValue, "Must provide different val");



            int256 previousValue = lever.currentValue;


            lever.currentValue = newValues[i];


            previousValues[i] = previousValue;
        }


        if (msg.value > 0) {
            safeFundsTransfer(platformAddress, msg.value);
        }


        if (controlToken.numRemainingUpdates > 0) {

            controlToken.numRemainingUpdates = controlToken.numRemainingUpdates - 1;


            if (pendingBids[controlTokenId].exists) {
                _withdrawBid(controlTokenId);
            }
        }


        emit ControlLeverUpdated(controlTokenId, msg.value, controlToken.numRemainingUpdates, leverIds, previousValues, newValues);
    }


    function withdrawAllFailedCredits() external {
        uint256 amount = failedTransferCredits[msg.sender];

        require(amount != 0);
        require(address(this).balance >= amount);

        failedTransferCredits[msg.sender] = 0;

        (bool successfulWithdraw, ) = msg.sender.call.value(amount)("");
        require(successfulWithdraw);
    }


    function safeFundsTransfer(address payable recipient, uint256 amount) internal {

        (bool success, ) = recipient.call.value(amount).gas(2300)("");

        if (success == false) {
            failedTransferCredits[recipient] = failedTransferCredits[recipient].add(amount);
        }
    }


    function _transferFrom(address from, address to, uint256 tokenId) internal {

        buyPrices[tokenId] = 0;

        super._transferFrom(from, to, tokenId);
    }
}

pragma solidity ^0.5.12;

library Roles {
	struct Role {
		mapping (address => bool) bearer;
	}


	function add(Role storage role, address account) internal {
		require(account != address(0));
		require(!has(role, account));

		role.bearer[account] = true;
	}


	function remove(Role storage role, address account) internal {
		require(account != address(0));
		require(has(role, account));

		role.bearer[account] = false;
	}


	function has(Role storage role, address account) internal view returns (bool) {
		require(account != address(0));
		return role.bearer[account];
	}
}

contract OTCRoles {
	using Roles for Roles.Role;

	constructor() internal {
		_addOwner(msg.sender);
	}


	event OwnerAdded(address indexed account);
	event OwnerRemoved(address indexed account);

	Roles.Role private _owners;

	modifier onlyOwner() {
		require(isOwner(msg.sender), "Sender is not owner");
		_;
	}

	function isOwner(address account) public view returns (bool) {
		return _owners.has(account);
	}

	function addOwner(address account) public onlyOwner {
		_addOwner(account);
	}

	function renounceOwner() public {
		_removeOwner(msg.sender);
	}

	function _addOwner(address account) internal {
		_owners.add(account);
		emit OwnerAdded(account);
	}

	function _removeOwner(address account) internal {
		_owners.remove(account);
		emit OwnerRemoved(account);
	}
}


interface IERC20 {

    function totalSupply() external view returns (uint256);


    function balanceOf(address account) external view returns (uint256);


    function transfer(address recipient, uint256 amount) external returns (bool);


    function allowance(address owner, address spender) external view returns (uint256);


    function approve(address spender, uint256 amount) external returns (bool);


    function transferFrom(address sender, address recipient, uint256 amount) external returns (bool);


    event Transfer(address indexed from, address indexed to, uint256 value);


    event Approval(address indexed owner, address indexed spender, uint256 value);
}


library SafeMath {

    function add(uint256 a, uint256 b) internal pure returns (uint256) {
        uint256 c = a + b;
        require(c >= a, "SafeMath: addition overflow");

        return c;
    }


    function sub(uint256 a, uint256 b) internal pure returns (uint256) {
        return sub(a, b, "SafeMath: subtraction overflow");
    }


    function sub(uint256 a, uint256 b, string memory errorMessage) internal pure returns (uint256) {
        require(b <= a, errorMessage);
        uint256 c = a - b;

        return c;
    }


    function mul(uint256 a, uint256 b) internal pure returns (uint256) {



        if (a == 0) {
            return 0;
        }

        uint256 c = a * b;
        require(c / a == b, "SafeMath: multiplication overflow");

        return c;
    }


    function div(uint256 a, uint256 b) internal pure returns (uint256) {
        return div(a, b, "SafeMath: division by zero");
    }


    function div(uint256 a, uint256 b, string memory errorMessage) internal pure returns (uint256) {
        require(b > 0, errorMessage);
        uint256 c = a / b;


        return c;
    }


    function mod(uint256 a, uint256 b) internal pure returns (uint256) {
        return mod(a, b, "SafeMath: modulo by zero");
    }


    function mod(uint256 a, uint256 b, string memory errorMessage) internal pure returns (uint256) {
        require(b != 0, errorMessage);
        return a % b;
    }
}


library Address {

    function isContract(address account) internal view returns (bool) {



        bytes32 codehash;
        bytes32 accountHash = 0xc5d2460186f7233c927e7db2dcc703c0e500b653ca82273b7bfad8045d85a470;

        assembly { codehash := extcodehash(account) }
        return (codehash != accountHash && codehash != 0x0);
    }


    function sendValue(address payable recipient, uint256 amount) internal {
        require(address(this).balance >= amount, "Address: insufficient balance");


        (bool success, ) = recipient.call.value(amount)("");
        require(success, "Address: unable to send value, recipient may have reverted");
    }


    function functionCall(address target, bytes memory data) internal returns (bytes memory) {
      return functionCall(target, data, "Address: low-level call failed");
    }


    function functionCall(address target, bytes memory data, string memory errorMessage) internal returns (bytes memory) {
        return _functionCallWithValue(target, data, 0, errorMessage);
    }


    function functionCallWithValue(address target, bytes memory data, uint256 value) internal returns (bytes memory) {
        return functionCallWithValue(target, data, value, "Address: low-level call with value failed");
    }


    function functionCallWithValue(address target, bytes memory data, uint256 value, string memory errorMessage) internal returns (bytes memory) {
        require(address(this).balance >= value, "Address: insufficient balance for call");
        return _functionCallWithValue(target, data, value, errorMessage);
    }

    function _functionCallWithValue(address target, bytes memory data, uint256 weiValue, string memory errorMessage) private returns (bytes memory) {
        require(isContract(target), "Address: call to non-contract");


        (bool success, bytes memory returndata) = target.call.value(weiValue)(data);
        if (success) {
            return returndata;
        } else {

            if (returndata.length > 0) {



                assembly {
                    let returndata_size := mload(returndata)
                    revert(add(32, returndata), returndata_size)
                }
            } else {
                revert(errorMessage);
            }
        }
    }
}


library SafeERC20 {
    using SafeMath for uint256;
    using Address for address;

    function safeTransfer(IERC20 token, address to, uint256 value) internal {
        _callOptionalReturn(token, abi.encodeWithSelector(token.transfer.selector, to, value));
    }

    function safeTransferFrom(IERC20 token, address from, address to, uint256 value) internal {
        _callOptionalReturn(token, abi.encodeWithSelector(token.transferFrom.selector, from, to, value));
    }


    function safeApprove(IERC20 token, address spender, uint256 value) internal {




        require((value == 0) || (token.allowance(address(this), spender) == 0),
            "SafeERC20: approve from non-zero to non-zero allowance"
        );
        _callOptionalReturn(token, abi.encodeWithSelector(token.approve.selector, spender, value));
    }

    function safeIncreaseAllowance(IERC20 token, address spender, uint256 value) internal {
        uint256 newAllowance = token.allowance(address(this), spender).add(value);
        _callOptionalReturn(token, abi.encodeWithSelector(token.approve.selector, spender, newAllowance));
    }

    function safeDecreaseAllowance(IERC20 token, address spender, uint256 value) internal {
        uint256 newAllowance = token.allowance(address(this), spender).sub(value, "SafeERC20: decreased allowance below zero");
        _callOptionalReturn(token, abi.encodeWithSelector(token.approve.selector, spender, newAllowance));
    }


    function _callOptionalReturn(IERC20 token, bytes memory data) private {




        bytes memory returndata = address(token).functionCall(data, "SafeERC20: low-level call failed");
        if (returndata.length > 0) { 

            require(abi.decode(returndata, (bool)), "SafeERC20: ERC20 operation did not succeed");
        }
    }
}




contract DIACompanyLockup is OTCRoles {
    using SafeERC20 for IERC20;
    IERC20 token;



    uint256 beginDepositTime;
    uint256 endDepositTime;


    address yieldWallet;


    address kickerWallet;
    uint256 kickerDeadline;
    uint256 kickerPromille;


    uint256 public threeMonthPromille;
    uint256 public sixMonthPromille;
    uint256 public nineMonthPromille;


    struct LockBoxStruct {
        address beneficiary;
        uint balance;
        uint releaseTime;
    }

    LockBoxStruct[] public lockBoxStructs; 

    event LogLockupDeposit(address sender, address beneficiary, uint amount, uint releaseTime);   
    event LogLockupWithdrawal(address receiver, uint amount);

    constructor(address tokenContract, uint256 _beginDepositTime, uint256 _endDepositTime, address _kickerWallet, uint256 _kickerDeadline, uint256 _kickerPromille, address _yieldWallet) public {
        token = IERC20(tokenContract);
        beginDepositTime = _beginDepositTime;
        endDepositTime = _endDepositTime;

        kickerWallet = _kickerWallet;
        kickerDeadline = _kickerDeadline;
        kickerPromille = _kickerPromille;
        yieldWallet = _yieldWallet;
    }

    function getLockBoxBeneficiary(uint256 lockBoxNumber) public view returns(address) {
        return lockBoxStructs[lockBoxNumber].beneficiary;
    }


    function deposit3m(address beneficiary, uint256 amount) public {
        deposit(beneficiary, amount, 12 weeks);
    }

    function deposit6m(address beneficiary, uint256 amount) public {
        deposit(beneficiary, amount, 24 weeks);
    }

    function deposit9m(address beneficiary, uint256 amount) public {
        deposit(beneficiary, amount, 36 weeks);
    }

    function deposit(address beneficiary, uint256 amount, uint256 duration) internal {
        require(now < endDepositTime, "Deposit time has ended.");

        uint256 yieldAmount;
        if (duration == 12 weeks) {
            yieldAmount = (threeMonthPromille * amount) / 1000;
        } else if (duration == 24 weeks) {
            yieldAmount = (sixMonthPromille * amount) / 1000;
        } else if (duration == 36 weeks) {
            yieldAmount = (nineMonthPromille * amount) / 1000;
        } else {
            revert("Error: duration not allowed!");
        }
        require(token.transferFrom(yieldWallet, address(this), yieldAmount));


        uint256 kickerAmount = (kickerPromille * amount) / 1000;
        if (now <= kickerDeadline) {
            require(token.transferFrom(kickerWallet, address(this), kickerAmount));
        }


        require(token.transferFrom(msg.sender, address(this), amount));


        LockBoxStruct memory l;
        l.beneficiary = beneficiary;
        l.balance = amount + kickerAmount + yieldAmount;
        l.releaseTime = beginDepositTime + duration;
        lockBoxStructs.push(l);
        emit LogLockupDeposit(msg.sender, l.beneficiary, l.balance, l.releaseTime);
    }


    function updateBeneficiary(uint256 lockBoxNumber, address newBeneficiary) public {
        LockBoxStruct storage l = lockBoxStructs[lockBoxNumber];
        require(msg.sender == l.beneficiary);
        l.beneficiary = newBeneficiary;
    }

    function withdraw(uint lockBoxNumber) public {
        LockBoxStruct storage l = lockBoxStructs[lockBoxNumber];
        require(l.releaseTime <= now);
        uint amount = l.balance;
        l.balance = 0;
        emit LogLockupWithdrawal(l.beneficiary, amount);
        require(token.transfer(l.beneficiary, amount));
    }


    function triggerWithdrawAll() public {

        for (uint256 i = 0; i < lockBoxStructs.length; ++i) {
            if (lockBoxStructs[i].releaseTime <= now && lockBoxStructs[i].balance > 0) {
                withdraw(i);
            }
        }
    }


    function updateEndDepositTime (uint256 newEndTime) public onlyOwner {
        endDepositTime = newEndTime;
    }

    function updateYieldWallet(address newWallet) public onlyOwner {
        yieldWallet = newWallet;
    }

    function updateKicker(address newWallet, uint256 newPromille, uint256 newDeadline) public onlyOwner {
        kickerWallet = newWallet;
        kickerPromille = newPromille;
        kickerDeadline = newDeadline;
    }

    function updateYields(uint256 threeMonths, uint256 sixMonths, uint256 nineMonths) public onlyOwner {
        threeMonthPromille = threeMonths;
        sixMonthPromille = sixMonths;
        nineMonthPromille = nineMonths;
    }


    function allocatePremium(uint256 lockBoxNumber, uint256 premiumAmount) public onlyOwner {
        LockBoxStruct storage l = lockBoxStructs[lockBoxNumber];
        require(l.releaseTime <= now);
        require(token.transferFrom(kickerWallet, address(this), premiumAmount));
        l.balance += premiumAmount;
    }
}

pragma solidity 0.4.24;

import "@aragon/os/contracts/common/EtherTokenConstant.sol";
import "@aragon/os/contracts/lib/token/ERC20.sol";
import "@aragon/templates-shared/contracts/BaseTemplate.sol";
import "@aragon/apps-agent/contracts/Agent.sol";
import "@ablack/fundraising-bancor-formula/contracts/BancorFormula.sol";
import {AragonFundraisingController as Controller} from "@ablack/fundraising-aragon-fundraising/contracts/AragonFundraisingController.sol";
import {BatchedBancorMarketMaker as MarketMaker} from "@ablack/fundraising-batched-bancor-market-maker/contracts/BatchedBancorMarketMaker.sol";
import "@ablack/fundraising-presale/contracts/Presale.sol";
import "@ablack/fundraising-tap/contracts/Tap.sol";


contract FundraisingMultisigTemplate is EtherTokenConstant, BaseTemplate {
    string    private constant ERROR_BAD_SETTINGS     = "FM_BAD_SETTINGS";
    string    private constant ERROR_MISSING_CACHE    = "FM_MISSING_CACHE";

    bool      private constant BOARD_TRANSFERABLE     = false;
    uint8     private constant BOARD_TOKEN_DECIMALS   = uint8(0);
    uint256   private constant BOARD_MAX_PER_ACCOUNT  = uint256(1);

    bool      private constant SHARE_TRANSFERABLE     = true;
    uint8     private constant SHARE_TOKEN_DECIMALS   = uint8(18);
    uint256   private constant SHARE_MAX_PER_ACCOUNT  = uint256(0);

    uint64    private constant DEFAULT_FINANCE_PERIOD = uint64(30 days);

    uint256   private constant BUY_FEE_PCT            = 0;
    uint256   private constant SELL_FEE_PCT           = 0;

    uint32    private constant DAI_RESERVE_RATIO      = 100000; 
    uint32    private constant ANT_RESERVE_RATIO      = 10000;  

    bytes32   private constant BANCOR_FORMULA_ID      = 0xd71dde5e4bea1928026c1779bde7ed27bd7ef3d0ce9802e4117631eb6fa4ed7d;
    bytes32   private constant PRESALE_ID             = 0x5de9bbdeaf6584c220c7b7f1922383bcd8bbcd4b48832080afd9d5ebf9a04df5;
    bytes32   private constant MARKET_MAKER_ID        = 0xc2bb88ab974c474221f15f691ed9da38be2f5d37364180cec05403c656981bf0;
    bytes32   private constant ARAGON_FUNDRAISING_ID  = 0x668ac370eed7e5861234d1c0a1e512686f53594fcb887e5bcecc35675a4becac;
    bytes32   private constant TAP_ID                 = 0x82967efab7144b764bc9bca2f31a721269b6618c0ff4e50545737700a5e9c9dc;

    struct Cache {
        address dao;
        address boardTokenManager;
        address boardVoting;
        address vault;
        address finance;
        address shareVoting;
        address shareTokenManager;
        address reserve;
        address presale;
        address marketMaker;
        address tap;
        address controller;
    }

    address[] public collaterals;
    mapping (address => Cache) private cache;

    constructor(
        DAOFactory              _daoFactory,
        ENS                     _ens,
        MiniMeTokenFactory      _miniMeFactory,
        IFIFSResolvingRegistrar _aragonID,
        address                 _dai,
        address                 _ant
    )
        BaseTemplate(_daoFactory, _ens, _miniMeFactory, _aragonID)
        public
    {
        _ensureAragonIdIsValid(_aragonID);
        _ensureMiniMeFactoryIsValid(_miniMeFactory);
        _ensureTokenIsContractOrETH(_dai);
        _ensureTokenIsContractOrETH(_ant);

        collaterals.push(address(_dai));
        collaterals.push(address(_ant));
    }



    function prepareInstance(
        string    _boardTokenName,
        string    _boardTokenSymbol,
        address[] _boardMembers,
        uint64[3] _boardVotingSettings,
        uint64    _financePeriod
    )
        external
    {
        require(_boardMembers.length > 0,         ERROR_BAD_SETTINGS);
        require(_boardVotingSettings.length == 3, ERROR_BAD_SETTINGS);


        (Kernel dao, ACL acl) = _createDAO();

        MiniMeToken boardToken = _createToken(_boardTokenName, _boardTokenSymbol, BOARD_TOKEN_DECIMALS);

        TokenManager tm = _installBoardApps(dao, boardToken, _boardVotingSettings, _financePeriod);

        _mintTokens(acl, tm, _boardMembers, 1);

        _cacheDao(dao);
    }

    function installShareApps(
        string    _shareTokenName,
        string    _shareTokenSymbol,
        uint64[3] _shareVotingSettings
    )
        external
    {
        require(_shareVotingSettings.length == 3, ERROR_BAD_SETTINGS);
        _ensureBoardAppsCache();

        Kernel dao = _daoCache();

        MiniMeToken shareToken = _createToken(_shareTokenName, _shareTokenSymbol, SHARE_TOKEN_DECIMALS);

        _installShareApps(dao, shareToken, _shareVotingSettings);

        _setupBoardPermissions(dao);
    }

    function installFundraisingApps(
        uint256 _goal,
        uint64  _period,
        uint256 _exchangeRate,
        uint64  _vestingCliffPeriod,
        uint64  _vestingCompletePeriod,
        uint256 _supplyOfferedPct,
        uint256 _fundingForBeneficiaryPct,
        uint64  _openDate,
        uint256 _batchBlocks,
        uint256 _maxTapRateIncreasePct,
        uint256 _maxTapFloorDecreasePct
    )
        external
    {
        _ensureShareAppsCache();

        Kernel dao = _daoCache();

        _installFundraisingApps(
            dao,
            _goal,
            _period,
            _exchangeRate,
            _vestingCliffPeriod,
            _vestingCompletePeriod,
            _supplyOfferedPct,
            _fundingForBeneficiaryPct,
            _openDate,
            _batchBlocks,
            _maxTapRateIncreasePct,
            _maxTapFloorDecreasePct
        );

        _setupSharePermissions(dao);

        _setupFundraisingPermissions(dao);
    }

    function finalizeInstance(
        string     _id,
        uint256[2] _virtualSupplies,
        uint256[2] _virtualBalances,
        uint256[2] _slippages,
        uint256    _rateDAI,
        uint256    _floorDAI
    )
        external
    {
        require(bytes(_id).length > 0,        ERROR_BAD_SETTINGS);
        require(_virtualSupplies.length == 2, ERROR_BAD_SETTINGS);
        require(_virtualBalances.length == 2, ERROR_BAD_SETTINGS);
        require(_slippages.length == 2,       ERROR_BAD_SETTINGS);
        _ensureFundraisingAppsCache();

        Kernel dao = _daoCache();
        ACL acl = ACL(dao.acl());
        (, Voting shareVoting) = _shareAppsCache();


        _setupCollaterals(dao, _virtualSupplies, _virtualBalances, _slippages, _rateDAI, _floorDAI);

        _createEvmScriptsRegistryPermissions(acl, shareVoting, shareVoting);

        _transferRootPermissionsFromTemplateAndFinalizeDAO(dao, shareVoting, shareVoting);

        _registerID(_id, address(dao));

        _clearCache();
    }



    function _installBoardApps(Kernel _dao, MiniMeToken _token, uint64[3] _votingSettings, uint64 _financePeriod)
        internal
        returns (TokenManager)
    {
        TokenManager tm = _installTokenManagerApp(_dao, _token, BOARD_TRANSFERABLE, BOARD_MAX_PER_ACCOUNT);
        Voting voting = _installVotingApp(_dao, _token, _votingSettings);
        Vault vault = _installVaultApp(_dao);
        Finance finance = _installFinanceApp(_dao, vault, _financePeriod == 0 ? DEFAULT_FINANCE_PERIOD : _financePeriod);

        _cacheBoardApps(tm, voting, vault, finance);

        return tm;
    }

    function _installShareApps(Kernel _dao, MiniMeToken _shareToken, uint64[3] _shareVotingSettings)
        internal
    {
        TokenManager tm = _installTokenManagerApp(_dao, _shareToken, SHARE_TRANSFERABLE, SHARE_MAX_PER_ACCOUNT);
        Voting voting = _installVotingApp(_dao, _shareToken, _shareVotingSettings);

        _cacheShareApps(tm, voting);
    }

    function _installFundraisingApps(
        Kernel  _dao,
        uint256 _goal,
        uint64  _period,
        uint256 _exchangeRate,
        uint64  _vestingCliffPeriod,
        uint64  _vestingCompletePeriod,
        uint256 _supplyOfferedPct,
        uint256 _fundingForBeneficiaryPct,
        uint64  _openDate,
        uint256 _batchBlocks,
        uint256 _maxTapRateIncreasePct,
        uint256 _maxTapFloorDecreasePct
    )
        internal
    {
        _proxifyFundraisingApps(_dao);

        _initializePresale(
            _goal,
            _period,
            _exchangeRate,
            _vestingCliffPeriod,
            _vestingCompletePeriod,
            _supplyOfferedPct,
            _fundingForBeneficiaryPct,
            _openDate
        );
        _initializeMarketMaker(_batchBlocks);
        _initializeTap(_batchBlocks, _maxTapRateIncreasePct, _maxTapFloorDecreasePct);
        _initializeController();
    }

    function _proxifyFundraisingApps(Kernel _dao) internal {
        Agent reserve = _installNonDefaultAgentApp(_dao);
        Presale presale = Presale(_registerApp(_dao, PRESALE_ID));
        MarketMaker marketMaker = MarketMaker(_registerApp(_dao, MARKET_MAKER_ID));
        Tap tap = Tap(_registerApp(_dao, TAP_ID));
        Controller controller = Controller(_registerApp(_dao, ARAGON_FUNDRAISING_ID));

        _cacheFundraisingApps(reserve, presale, marketMaker, tap, controller);
    }



    function _initializePresale(
        uint256 _goal,
        uint64  _period,
        uint256 _exchangeRate,
        uint64  _vestingCliffPeriod,
        uint64  _vestingCompletePeriod,
        uint256 _supplyOfferedPct,
        uint256 _fundingForBeneficiaryPct,
        uint64  _openDate
    )
        internal
    {
        _presaleCache().initialize(
            _controllerCache(),
            _shareTMCache(),
            _reserveCache(),
            _vaultCache(),
            collaterals[0],
            _goal,
            _period,
            _exchangeRate,
            _vestingCliffPeriod,
            _vestingCompletePeriod,
            _supplyOfferedPct,
            _fundingForBeneficiaryPct,
            _openDate
        );
    }

    function _initializeMarketMaker(uint256 _batchBlocks) internal {
        IBancorFormula bancorFormula = IBancorFormula(_latestVersionAppBase(BANCOR_FORMULA_ID));

        (,, Vault beneficiary,) = _boardAppsCache();
        (TokenManager shareTM,) = _shareAppsCache();
        (Agent reserve,, MarketMaker marketMaker,, Controller controller) = _fundraisingAppsCache();

        marketMaker.initialize(controller, shareTM, bancorFormula, reserve, beneficiary, _batchBlocks, BUY_FEE_PCT, SELL_FEE_PCT);
    }

    function _initializeTap(uint256 _batchBlocks, uint256 _maxTapRateIncreasePct, uint256 _maxTapFloorDecreasePct) internal {
        (,, Vault beneficiary,) = _boardAppsCache();
        (Agent reserve,,, Tap tap, Controller controller) = _fundraisingAppsCache();

        tap.initialize(controller, reserve, beneficiary, _batchBlocks, _maxTapRateIncreasePct, _maxTapFloorDecreasePct);
    }

    function _initializeController() internal {
        (Agent reserve, Presale presale, MarketMaker marketMaker, Tap tap, Controller controller) = _fundraisingAppsCache();
        address[] memory toReset = new address[](1);
        toReset[0] = collaterals[0];
        controller.initialize(presale, marketMaker, reserve, tap, toReset);
    }



    function _setupCollaterals(
        Kernel     _dao,
        uint256[2] _virtualSupplies,
        uint256[2] _virtualBalances,
        uint256[2] _slippages,
        uint256    _rateDAI,
        uint256    _floorDAI
    )
        internal
    {
        ACL acl = ACL(_dao.acl());
        (, Voting shareVoting) = _shareAppsCache();
        (,,,, Controller controller) = _fundraisingAppsCache();



        acl.createPermission(this, controller, controller.ADD_COLLATERAL_TOKEN_ROLE(), this);

        controller.addCollateralToken(
            collaterals[0],
            _virtualSupplies[0],
            _virtualBalances[0],
            DAI_RESERVE_RATIO,
            _slippages[0],
            _rateDAI,
            _floorDAI
        );

        controller.addCollateralToken(
            collaterals[1],
            _virtualSupplies[1],
            _virtualBalances[1],
            ANT_RESERVE_RATIO,
            _slippages[1],
            0,
            0
        );

        _transferPermissionFromTemplate(acl, controller, shareVoting, controller.ADD_COLLATERAL_TOKEN_ROLE(), shareVoting);
    }



    function _setupBoardPermissions(Kernel _dao) internal {
        ACL acl = ACL(_dao.acl());

        (TokenManager boardTM, Voting boardVoting, Vault vault, Finance finance) = _boardAppsCache();
        (, Voting shareVoting) = _shareAppsCache();


        _createTokenManagerPermissions(acl, boardTM, boardVoting, shareVoting);

        _createVotingPermissions(acl, boardVoting, boardVoting, boardTM, shareVoting);

        _createVaultPermissions(acl, vault, finance, shareVoting);

        _createFinancePermissions(acl, finance, boardVoting, shareVoting);
        _createFinanceCreatePaymentsPermission(acl, finance, boardVoting, shareVoting);
    }

    function _setupSharePermissions(Kernel _dao) internal {
        ACL acl = ACL(_dao.acl());

        (TokenManager boardTM,,,) = _boardAppsCache();
        (TokenManager shareTM, Voting shareVoting) = _shareAppsCache();
        (, Presale presale, MarketMaker marketMaker,,) = _fundraisingAppsCache();


        address[] memory grantees = new address[](2);
        grantees[0] = address(marketMaker);
        grantees[1] = address(presale);
        acl.createPermission(marketMaker, shareTM, shareTM.MINT_ROLE(),shareVoting);
        acl.createPermission(presale, shareTM, shareTM.ISSUE_ROLE(),shareVoting);
        acl.createPermission(presale, shareTM, shareTM.ASSIGN_ROLE(),shareVoting);
        acl.createPermission(presale, shareTM, shareTM.REVOKE_VESTINGS_ROLE(), shareVoting);
        _createPermissions(acl, grantees, shareTM, shareTM.BURN_ROLE(), shareVoting);

        _createVotingPermissions(acl, shareVoting, shareVoting, boardTM, shareVoting);
    }

    function _setupFundraisingPermissions(Kernel _dao) internal {
        ACL acl = ACL(_dao.acl());

        (, Voting boardVoting,,) = _boardAppsCache();
        (, Voting shareVoting) = _shareAppsCache();
        (Agent reserve, Presale presale, MarketMaker marketMaker, Tap tap, Controller controller) = _fundraisingAppsCache();


        address[] memory grantees = new address[](2);
        grantees[0] = address(tap);
        grantees[1] = address(marketMaker);
        acl.createPermission(shareVoting, reserve, reserve.SAFE_EXECUTE_ROLE(), shareVoting);
        acl.createPermission(controller, reserve, reserve.ADD_PROTECTED_TOKEN_ROLE(), shareVoting);
        _createPermissions(acl, grantees, reserve, reserve.TRANSFER_ROLE(), shareVoting);

        acl.createPermission(controller, presale, presale.OPEN_ROLE(), shareVoting);
        acl.createPermission(controller, presale, presale.CONTRIBUTE_ROLE(), shareVoting);

        acl.createPermission(controller, marketMaker, marketMaker.OPEN_ROLE(), shareVoting);
        acl.createPermission(controller, marketMaker, marketMaker.UPDATE_BENEFICIARY_ROLE(), shareVoting);
        acl.createPermission(controller, marketMaker, marketMaker.UPDATE_FEES_ROLE(), shareVoting);
        acl.createPermission(controller, marketMaker, marketMaker.ADD_COLLATERAL_TOKEN_ROLE(), shareVoting);
        acl.createPermission(controller, marketMaker, marketMaker.REMOVE_COLLATERAL_TOKEN_ROLE(), shareVoting);
        acl.createPermission(controller, marketMaker, marketMaker.UPDATE_COLLATERAL_TOKEN_ROLE(), shareVoting);
        acl.createPermission(controller, marketMaker, marketMaker.OPEN_BUY_ORDER_ROLE(), shareVoting);
        acl.createPermission(controller, marketMaker, marketMaker.OPEN_SELL_ORDER_ROLE(), shareVoting);

        acl.createPermission(controller, tap, tap.UPDATE_BENEFICIARY_ROLE(), shareVoting);
        acl.createPermission(controller, tap, tap.UPDATE_MAXIMUM_TAP_RATE_INCREASE_PCT_ROLE(), shareVoting);
        acl.createPermission(controller, tap, tap.UPDATE_MAXIMUM_TAP_FLOOR_DECREASE_PCT_ROLE(), shareVoting);
        acl.createPermission(controller, tap, tap.ADD_TAPPED_TOKEN_ROLE(), shareVoting);
        acl.createPermission(controller, tap, tap.UPDATE_TAPPED_TOKEN_ROLE(), shareVoting);
        acl.createPermission(controller, tap, tap.RESET_TAPPED_TOKEN_ROLE(), shareVoting);
        acl.createPermission(controller, tap, tap.WITHDRAW_ROLE(), shareVoting);


        acl.createPermission(shareVoting, controller, controller.UPDATE_BENEFICIARY_ROLE(), shareVoting);
        acl.createPermission(shareVoting, controller, controller.UPDATE_FEES_ROLE(), shareVoting);

        acl.createPermission(shareVoting, controller, controller.REMOVE_COLLATERAL_TOKEN_ROLE(), shareVoting);
        acl.createPermission(shareVoting, controller, controller.UPDATE_COLLATERAL_TOKEN_ROLE(), shareVoting);
        acl.createPermission(shareVoting, controller, controller.UPDATE_MAXIMUM_TAP_RATE_INCREASE_PCT_ROLE(), shareVoting);
        acl.createPermission(shareVoting, controller, controller.UPDATE_MAXIMUM_TAP_FLOOR_DECREASE_PCT_ROLE(), shareVoting);
        acl.createPermission(shareVoting, controller, controller.ADD_TOKEN_TAP_ROLE(), shareVoting);
        acl.createPermission(shareVoting, controller, controller.UPDATE_TOKEN_TAP_ROLE(), shareVoting);
        acl.createPermission(boardVoting, controller, controller.OPEN_PRESALE_ROLE(), shareVoting);
        acl.createPermission(presale, controller, controller.OPEN_TRADING_ROLE(), shareVoting);
        acl.createPermission(address(-1), controller, controller.CONTRIBUTE_ROLE(), shareVoting);
        acl.createPermission(address(-1), controller, controller.OPEN_BUY_ORDER_ROLE(), shareVoting);
        acl.createPermission(address(-1), controller, controller.OPEN_SELL_ORDER_ROLE(), shareVoting);
        acl.createPermission(address(-1), controller, controller.WITHDRAW_ROLE(), shareVoting);
    }



    function _cacheDao(Kernel _dao) internal {
        Cache storage c = cache[msg.sender];

        c.dao = address(_dao);
    }

    function _cacheBoardApps(TokenManager _boardTM, Voting _boardVoting, Vault _vault, Finance _finance) internal {
        Cache storage c = cache[msg.sender];

        c.boardTokenManager = address(_boardTM);
        c.boardVoting = address(_boardVoting);
        c.vault = address(_vault);
        c.finance = address(_finance);
    }

    function _cacheShareApps(TokenManager _shareTM, Voting _shareVoting) internal {
        Cache storage c = cache[msg.sender];

        c.shareTokenManager = address(_shareTM);
        c.shareVoting = address(_shareVoting);
    }

    function _cacheFundraisingApps(Agent _reserve, Presale _presale, MarketMaker _marketMaker, Tap _tap, Controller _controller) internal {
        Cache storage c = cache[msg.sender];

        c.reserve = address(_reserve);
        c.presale = address(_presale);
        c.marketMaker = address(_marketMaker);
        c.tap = address(_tap);
        c.controller = address(_controller);
    }

    function _daoCache() internal returns (Kernel dao) {
        Cache storage c = cache[msg.sender];

        dao = Kernel(c.dao);
    }

    function _boardAppsCache() internal returns (TokenManager boardTM, Voting boardVoting, Vault vault, Finance finance) {
        Cache storage c = cache[msg.sender];

        boardTM = TokenManager(c.boardTokenManager);
        boardVoting = Voting(c.boardVoting);
        vault = Vault(c.vault);
        finance = Finance(c.finance);
    }

    function _shareAppsCache() internal returns (TokenManager shareTM, Voting shareVoting) {
        Cache storage c = cache[msg.sender];

        shareTM = TokenManager(c.shareTokenManager);
        shareVoting = Voting(c.shareVoting);
    }

    function _fundraisingAppsCache() internal returns (Agent reserve, Presale presale, MarketMaker marketMaker, Tap tap, Controller controller) {
        Cache storage c = cache[msg.sender];

        reserve = Agent(c.reserve);
        presale = Presale(c.presale);
        marketMaker = MarketMaker(c.marketMaker);
        tap = Tap(c.tap);
        controller = Controller(c.controller);
    }

    function _clearCache() internal {
        Cache storage c = cache[msg.sender];

        delete c.dao;
        delete c.boardTokenManager;
        delete c.boardVoting;
        delete c.vault;
        delete c.finance;
        delete c.shareVoting;
        delete c.shareTokenManager;
        delete c.reserve;
        delete c.presale;
        delete c.marketMaker;
        delete c.tap;
        delete c.controller;
    }



    function _vaultCache() internal returns (Vault vault) {
        Cache storage c = cache[msg.sender];

        vault = Vault(c.vault);
    }

    function _shareTMCache() internal returns (TokenManager shareTM) {
        Cache storage c = cache[msg.sender];

        shareTM = TokenManager(c.shareTokenManager);
    }

    function _reserveCache() internal returns (Agent reserve) {
        Cache storage c = cache[msg.sender];

        reserve = Agent(c.reserve);
    }

    function _presaleCache() internal returns (Presale presale) {
        Cache storage c = cache[msg.sender];

        presale = Presale(c.presale);
    }

    function _controllerCache() internal returns (Controller controller) {
        Cache storage c = cache[msg.sender];

        controller = Controller(c.controller);
    }



     function _ensureTokenIsContractOrETH(address _token) internal view returns (bool) {
        require(isContract(_token) || _token == ETH, ERROR_BAD_SETTINGS);
    }

    function _ensureBoardAppsCache() internal {
        Cache storage c = cache[msg.sender];
        require(
            c.boardTokenManager != address(0) &&
            c.boardVoting != address(0) &&
            c.vault != address(0) &&
            c.finance != address(0),
            ERROR_MISSING_CACHE
        );
    }

    function _ensureShareAppsCache() internal {
        Cache storage c = cache[msg.sender];
        require(
            c.shareTokenManager != address(0) &&
            c.shareVoting != address(0),
            ERROR_MISSING_CACHE
        );
    }

    function _ensureFundraisingAppsCache() internal {
        Cache storage c = cache[msg.sender];
        require(
            c.reserve != address(0) &&
            c.presale != address(0) &&
            c.marketMaker != address(0) &&
            c.tap != address(0) &&
            c.controller != address(0),
            ERROR_MISSING_CACHE
        );
    }



    function _registerApp(Kernel _dao, bytes32 _appId) internal returns (address) {
        address proxy = _dao.newAppInstance(_appId, _latestVersionAppBase(_appId));

        emit InstalledApp(proxy, _appId);

        return proxy;
    }
}

pragma solidity 0.5.0;
pragma experimental ABIEncoderV2;

import "./inherited/ERC20Token.sol";
import "./inherited/ERC721Basic.sol";




contract StandardBounties {



  struct Bounty {
    address payable [] issuers; 
    address [] approvers; 
    uint deadline; 
    address token; 
    uint tokenVersion; 
    uint balance; 
    bool hasPaidOut; 
    Fulfillment [] fulfillments; 
    Contribution [] contributions; 
  }

  struct Fulfillment {
    address payable [] fulfillers; 
    address submitter; 
  }

  struct Contribution {
    address payable contributor; 
    uint amount; 
    bool refunded; 
  }



  uint public numBounties; 
  mapping(uint => Bounty) public bounties; 

  address owner; 
  address metaTxRelayer; 




  modifier validateBountyArrayIndex(
    uint _index)
  {
    require(_index < numBounties);
    _;
  }

  modifier validateContributionArrayIndex(
    uint _bountyId,
    uint _index)
  {
    require(_index < bounties[_bountyId].contributions.length);
    _;
  }

  modifier validateFulfillmentArrayIndex(
    uint _bountyId,
    uint _index)
  {
    require(_index < bounties[_bountyId].fulfillments.length);
    _;
  }

  modifier validateIssuerArrayIndex(
    uint _bountyId,
    uint _index)
  {
    require(_index < bounties[_bountyId].issuers.length || _index == 0);
    _;
  }

  modifier validateApproverArrayIndex(
    uint _bountyId,
    uint _index)
  {
    require(_index < bounties[_bountyId].approvers.length || _index == 0);
    _;
  }

  modifier onlyIssuer(
  address _sender,
  uint _bountyId,
  uint _issuerId)
  {
  require(_sender == bounties[_bountyId].issuers[_issuerId]);
  _;
  }

  modifier onlySubmitter(
    address _sender,
    uint _bountyId,
    uint _fulfillmentId)
  {
    require(_sender ==
            bounties[_bountyId].fulfillments[_fulfillmentId].submitter);
    _;
  }

  modifier onlyContributor(
  address _sender,
  uint _bountyId,
  uint _contributionId)
  {
    require(_sender ==
            bounties[_bountyId].contributions[_contributionId].contributor);
    _;
  }

  modifier isApprover(
    address _sender,
    uint _bountyId,
    uint _approverId)
  {
    require(_sender == bounties[_bountyId].approvers[_approverId]);
    _;
  }

  modifier hasNotPaid(
    uint _bountyId)
  {
    require(!bounties[_bountyId].hasPaidOut);
    _;
  }

  modifier hasNotRefunded(
    uint _bountyId,
    uint _contributionId)
  {
    require(!bounties[_bountyId].contributions[_contributionId].refunded);
    _;
  }

  modifier senderIsValid(
    address _sender)
  {
    require(msg.sender == _sender || msg.sender == metaTxRelayer);
    _;
  }



  constructor() public {

    owner = msg.sender;
  }



  function setMetaTxRelayer(address _relayer)
    public
  {
    require(msg.sender == owner); 
    require(metaTxRelayer == address(0)); 
    metaTxRelayer = _relayer;
  }










  function issueBounty(
    address payable _sender,
    address payable [] memory _issuers,
    address [] memory _approvers,
    string memory _data,
    uint _deadline,
    address _token,
    uint _tokenVersion,
    uint _depositAmount)
    public
    payable
    senderIsValid(_sender)
    returns (uint)
  {
    require(_tokenVersion == 0 || _tokenVersion == 20 || _tokenVersion == 721); 

    uint bountyId = numBounties; 

    Bounty storage newBounty = bounties[bountyId];
    newBounty.issuers = _issuers;
    newBounty.approvers = _approvers;
    newBounty.deadline = _deadline;
    newBounty.token = _token;
    newBounty.tokenVersion = _tokenVersion;

    numBounties++; 

    emit BountyIssued(bountyId,
    _sender,
    _issuers,
    _approvers,
    _data, 
    _deadline,
    _token,
    _tokenVersion);


    if (_depositAmount > 0){
      contribute(_sender, bountyId, _depositAmount);
    }
    return (bountyId);
  }











  function contribute(
    address payable _sender,
    uint _bountyId,
    uint _amount)
    public
    payable
    senderIsValid(_sender)
    validateBountyArrayIndex(_bountyId)
  {

    bounties[_bountyId].contributions.push(
      Contribution(_sender, _amount, false)); 

    bounties[_bountyId].balance += _amount; 

    require(_amount > 0); 

    if (bounties[_bountyId].tokenVersion == 0){
      require(msg.value == _amount);
    } else if (bounties[_bountyId].tokenVersion == 20) {
      require(msg.value == 0); 
      require(ERC20Token(bounties[_bountyId].token).transferFrom(_sender,
                                                                 address(this),
                                                                 _amount));
    } else if (bounties[_bountyId].tokenVersion == 721) {
      require(msg.value == 0); 
      ERC721BasicToken(bounties[_bountyId].token).transferFrom(_sender,
                                                               address(this),
                                                               _amount);
    }

    emit ContributionAdded(_bountyId,
                           bounties[_bountyId].contributions.length - 1, 
                           _sender,
                           _amount);
  }







  function refundContribution(
    address _sender,
    uint _bountyId,
    uint _contributionId)
    public
    senderIsValid(_sender)
    validateBountyArrayIndex(_bountyId)
    validateContributionArrayIndex(_bountyId, _contributionId)
    onlyContributor(_sender, _bountyId, _contributionId)
    hasNotPaid(_bountyId)
    hasNotRefunded(_bountyId, _contributionId)
  {
    require(now > bounties[_bountyId].deadline); 

    Contribution storage contribution =
      bounties[_bountyId].contributions[_contributionId];

    contribution.refunded = true;
    bounties[_bountyId].balance -= contribution.amount;

    transferTokens(_bountyId, contribution.contributor, contribution.amount); 

    emit ContributionRefunded(_bountyId, _contributionId);
  }





  function refundContributions(
    address _sender,
    uint _bountyId,
    uint [] memory _contributionIds)
    public
    senderIsValid(_sender)
  {
    for (uint i = 0; i < _contributionIds.length; i++){
      refundContribution(_sender, _bountyId, _contributionIds[i]);
    }
  }






  function performAction(
    address _sender,
    uint _bountyId,
    string memory _data)
    public
    senderIsValid(_sender)
    validateBountyArrayIndex(_bountyId)
  {
    emit ActionPerformed(_bountyId, _sender, _data); 
  }






  function fulfillBounty(
    address _sender,
    uint _bountyId,
    address payable [] memory  _fulfillers,
    string memory _data)
    public
    senderIsValid(_sender)
    validateBountyArrayIndex(_bountyId)
  {
    require(now < bounties[_bountyId].deadline); 
    require(_fulfillers.length > 0); 

    bounties[_bountyId].fulfillments.push(Fulfillment(_fulfillers, _sender));

    emit BountyFulfilled(_bountyId,
                         (bounties[_bountyId].fulfillments.length - 1),
                         _fulfillers,
                         _data, 
                         _sender);
  }







  function updateFulfillment(
  address _sender,
  uint _bountyId,
  uint _fulfillmentId,
  address payable [] memory _fulfillers,
  string memory _data)
  public
  senderIsValid(_sender)
  validateBountyArrayIndex(_bountyId)
  validateFulfillmentArrayIndex(_bountyId, _fulfillmentId)
  onlySubmitter(_sender, _bountyId, _fulfillmentId) 
  {
    bounties[_bountyId].fulfillments[_bountyId].fulfillers = _fulfillers;
    emit FulfillmentUpdated(_bountyId,
                            _fulfillmentId,
                            _fulfillers,
                            _data); 
  }











  function acceptFulfillment(
    address _sender,
    uint _bountyId,
    uint _fulfillmentId,
    uint _approverId,
    uint[] memory _tokenAmounts)
    public
    senderIsValid(_sender)
    validateBountyArrayIndex(_bountyId)
    validateFulfillmentArrayIndex(_bountyId, _fulfillmentId)
    isApprover(_sender, _bountyId, _approverId)
  {

    bounties[_bountyId].hasPaidOut = true;

    Fulfillment storage fulfillment =
      bounties[_bountyId].fulfillments[_fulfillmentId];

    require(_tokenAmounts.length == fulfillment.fulfillers.length); 

    for (uint256 i = 0; i < fulfillment.fulfillers.length; i++){

      require(bounties[_bountyId].balance >= _tokenAmounts[i]); 

      bounties[_bountyId].balance -= _tokenAmounts[i];

      if (_tokenAmounts[i] != 0){
        transferTokens(_bountyId, fulfillment.fulfillers[i], _tokenAmounts[i]);
      }
    }
    emit FulfillmentAccepted(_bountyId,
                             _fulfillmentId,
                             _sender,
                             _tokenAmounts);
  }












  function fulfillAndAccept(
    address _sender,
    uint _bountyId,
    address payable [] memory _fulfillers,
    string memory _data,
    uint _approverId,
    uint[] memory _tokenAmounts)
    public
    senderIsValid(_sender)
  {

    fulfillBounty(_sender, _bountyId, _fulfillers, _data);


    acceptFulfillment(_sender,
                      _bountyId,
                      bounties[_bountyId].fulfillments.length - 1,
                      _approverId,
                      _tokenAmounts);
  }











  function changeBounty(
    address _sender,
    uint _bountyId,
    uint _issuerId,
    address payable [] memory _issuers,
    address payable [] memory _approvers,
    string memory _data,
    uint _deadline)
    public
    senderIsValid(_sender)
    validateBountyArrayIndex(_bountyId)
    validateIssuerArrayIndex(_bountyId, _issuerId)
    onlyIssuer(_sender, _bountyId, _issuerId)
  {
    bounties[_bountyId].issuers = _issuers;
    bounties[_bountyId].approvers = _approvers;
    bounties[_bountyId].deadline = _deadline;
    emit BountyChanged(_bountyId,
                       _sender,
                       _issuers,
                       _approvers,
                       _data,
                       _deadline);
  }







  function changeIssuer(
    address _sender,
    uint _bountyId,
    uint _issuerId,
    uint _issuerIdToChange,
    address payable _newIssuer)
    public
    senderIsValid(_sender)
    validateBountyArrayIndex(_bountyId)
    validateIssuerArrayIndex(_bountyId, _issuerId)
    validateIssuerArrayIndex(_bountyId, _issuerIdToChange)
    onlyIssuer(_sender, _bountyId, _issuerId)
  {
    bounties[_bountyId].issuers[_issuerIdToChange] = _newIssuer;

    emit BountyIssuerChanged(_bountyId, _sender, _issuerId, _newIssuer);
  }







  function changeApprover(
    address _sender,
    uint _bountyId,
    uint _issuerId,
    uint _approverId,
    address payable _approver)
    public
    senderIsValid(_sender)
    validateBountyArrayIndex(_bountyId)
    validateIssuerArrayIndex(_bountyId, _issuerId)
    onlyIssuer(_sender, _bountyId, _issuerId)
    validateApproverArrayIndex(_bountyId, _approverId)
  {
    bounties[_bountyId].approvers[_approverId] = _approver;

    emit BountyApproverChanged(_bountyId,
              msg.sender,
              _approverId,
              _approver);
  }






  function changeData(
    address _sender,
    uint _bountyId,
    uint _issuerId,
    string memory _data)
    public
    senderIsValid(_sender)
    validateBountyArrayIndex(_bountyId)
    validateIssuerArrayIndex(_bountyId, _issuerId)
    onlyIssuer(_sender, _bountyId, _issuerId)
  {
    emit BountyDataChanged(_bountyId, msg.sender, _data); 
  }






  function changeDeadline(
    address _sender,
    uint _bountyId,
    uint _issuerId,
    uint _deadline)
    public
    senderIsValid(_sender)
    validateBountyArrayIndex(_bountyId)
    validateIssuerArrayIndex(_bountyId, _issuerId)
    onlyIssuer(_sender, _bountyId, _issuerId)
  {
    bounties[_bountyId].deadline = _deadline;

    emit BountyDeadlineChanged(_bountyId, _sender, _deadline);
  }






  function addIssuers(
    address _sender,
    uint _bountyId,
    uint _issuerId,
    address payable [] memory _issuers)
    public
    senderIsValid(_sender)
    validateBountyArrayIndex(_bountyId)
    validateIssuerArrayIndex(_bountyId, _issuerId)
    onlyIssuer(_sender, _bountyId, _issuerId)
  {
    for (uint i = 0; i < _issuers.length; i++){
      bounties[_bountyId].issuers.push(_issuers[i]);
    }
    emit BountyIssuersAdded(_bountyId, _sender, _issuers);
  }






  function replaceIssuers(
    address _sender,
    uint _bountyId,
    uint _issuerId,
    address payable [] memory _issuers)
    public
    senderIsValid(_sender)
    validateBountyArrayIndex(_bountyId)
    validateIssuerArrayIndex(_bountyId, _issuerId)
    onlyIssuer(_sender, _bountyId, _issuerId)
  {
    bounties[_bountyId].issuers = _issuers;

    emit BountyIssuersReplaced(_bountyId, _sender, _issuers);
  }






  function addApprovers(
  address _sender,
  uint _bountyId,
  uint _issuerId,
  address [] memory _approvers)
  public
  senderIsValid(_sender)
  validateBountyArrayIndex(_bountyId)
  validateIssuerArrayIndex(_bountyId, _issuerId)
  onlyIssuer(_sender, _bountyId, _issuerId)
  {
    for (uint i = 0; i < _approvers.length; i++){
      bounties[_bountyId].approvers.push(_approvers[i]);
    }
    emit BountyApproversAdded(_bountyId, _sender, _approvers);
  }






  function replaceApprovers(
  address _sender,
  uint _bountyId,
  uint _issuerId,
  address [] memory _approvers)
  public
  senderIsValid(_sender)
  validateBountyArrayIndex(_bountyId)
  validateIssuerArrayIndex(_bountyId, _issuerId)
  onlyIssuer(_sender, _bountyId, _issuerId)
  {
    bounties[_bountyId].approvers = _approvers;

    emit BountyApproversReplaced(_bountyId, _sender, _approvers);
  }




  function getBounty(uint _bountyId)
    public
    view
    returns (Bounty memory)
  {
    return bounties[_bountyId];
  }


  function transferTokens(uint _bountyId, address payable _to, uint _amount)
    internal
  {
    if (bounties[_bountyId].tokenVersion == 0){
      _to.transfer(_amount);
    } else if (bounties[_bountyId].tokenVersion == 20) {
      require(ERC20Token(bounties[_bountyId].token).transfer(_to, _amount));
    } else if (bounties[_bountyId].tokenVersion == 721) {
      ERC721BasicToken(bounties[_bountyId].token).safeTransferFrom(address(this),
                                                                   _to,
                                                                   _amount);
    } else {
      revert();
    }
  }



  event BountyIssued(uint _bountyId, address payable _creator, address payable [] _issuers, address [] _approvers, string _data, uint _deadline, address _token, uint _tokenVersion);
  event ContributionAdded(uint _bountyId, uint _contributionId, address payable _contributor, uint _amount);
  event ContributionRefunded(uint _bountyId, uint _contributionId);
  event ActionPerformed(uint _bountyId, address _fulfiller, string _data);
  event BountyFulfilled(uint _bountyId, uint _fulfillmentId, address payable [] _fulfillers, string _data, address _submitter);
  event FulfillmentUpdated(uint _bountyId, uint _fulfillmentId, address payable [] _fulfillers, string _data);
  event FulfillmentAccepted(uint _bountyId, uint  _fulfillmentId, address _approver, uint[] _tokenAmounts);
  event BountyChanged(uint _bountyId, address _changer, address payable [] _issuers, address payable [] _approvers, string _data, uint _deadline);
  event BountyIssuerChanged(uint _bountyId, address _changer, uint _issuerId, address payable _issuer);
  event BountyIssuersAdded(uint _bountyId, address _changer, address payable [] _issuers);
  event BountyIssuersReplaced(uint _bountyId, address _changer, address payable [] _issuers);
  event BountyApproverChanged(uint _bountyId, address payable _changer, uint _approverId, address payable _approver);
  event BountyApproversAdded(uint _bountyId, address _changer, address [] _approvers);
  event BountyApproversReplaced(uint _bountyId, address _changer, address [] _approvers);
  event BountyDataChanged(uint _bountyId, address _changer, string _data);
  event BountyDeadlineChanged(uint _bountyId, address _changer, uint _deadline);
}

