contract Oracula is Context, IBEP20, Ownable {



    uint256 private _totalSupply = 50 * 10 ** (6 + 18);

    string private _name = "Oracula";

    string private _symbol = "ORACULA";

    uint8 private _decimals = 18;



    IPancakeRouter02 public pancakeRouter;



    mapping(address => uint256) private _balances;



    mapping(address => mapping(address => uint256)) private _allowances;



    mapping(address => bool) public _isExcludedFromFees;



    mapping(address => bool) public exchangePairs;




    uint256 burnFee;

    uint256 devFee;

    uint256 rewardFee;

    uint256 immutable maxBurnFee = 20;

    uint256 immutable maxDevFee = 20;

    uint256 immutable maxRewardFee = 20;

    uint256 immutable maximumFee = 60;

    uint256 immutable denominator = 1000;

    address immutable burnAddress = 0x000000000000000000000000000000000000dEaD;

    address devAddress;

    address rewardAddress;



    uint256 public nextBurn;



    constructor(

        address _devAddress, 

        address _rewardAddress, 

        uint256 _burnFee, 

        uint256 _devFee, 

        uint256 _rewardFee

        ){

        _changeFeeAddresses(_devAddress, _rewardAddress);

        _changeAllFees(_burnFee, _devFee, _rewardFee);



        IPancakeRouter02 _pancakeRouter = IPancakeRouter02(0x10ED43C718714eb63d5aA57B78B54704E256024E);

        address _pancakePair = IPancakeFactory(_pancakeRouter.factory())

        .createPair(address(this), _pancakeRouter.WETH());



        pancakeRouter = _pancakeRouter;



		_setExchangePairs(_pancakePair, true);



        _changeFeeStatus(owner(), true);



        nextBurn = block.timestamp + 30 days;



        _balances[owner()] += _totalSupply;

        emit Transfer(address(0), owner(), _totalSupply);

    }





    function totalSupply() external override view returns (uint256) {

        return _totalSupply;

    }



    function getOwner() external view override returns (address) {

        return owner();

    }





    function decimals() external override view returns (uint8){

        return _decimals;

    }





    function symbol() external override view returns (string memory) {

        return _symbol;

    }





    function name() external override view returns (string memory) {

        return _name;

    }



    function getFees() external view returns (uint256 burn, uint256 dev, uint256 reward) {

        return (burnFee, devFee, rewardFee);

    }





    function getSumOfFees() public view returns (uint256) {

        return burnFee + devFee + rewardFee;

    }



    function transfer(address recipient, uint256 amount) public virtual override returns (bool) {

        _transfer(_msgSender(), recipient, amount);

        return true;

    }





    function allowance(address owner, address spender) public view virtual override returns (uint256) {

        return _allowances[owner][spender];

    }



    function approve(address spender, uint256 amount) public virtual override returns (bool) {

        _approve(_msgSender(), spender, amount);

        return true;

    }



    function transferFrom(

        address sender,

        address recipient,

        uint256 amount

    ) public virtual override returns (bool) {

        _transfer(sender, recipient, amount);



        uint256 currentAllowance = _allowances[sender][_msgSender()];

        require(currentAllowance >= amount, "BEP20: transfer amount exceeds allowance");

        unchecked {

            _approve(sender, _msgSender(), currentAllowance - amount);

        }



        return true;

    }



    function increaseAllowance(address spender, uint256 addedValue) public virtual returns (bool) {

        _approve(_msgSender(), spender, _allowances[_msgSender()][spender] + addedValue);

        return true;

    }



    function decreaseAllowance(address spender, uint256 subtractedValue) public virtual returns (bool) {

        uint256 currentAllowance = _allowances[_msgSender()][spender];

        require(currentAllowance >= subtractedValue, "BEP20: decreased allowance below zero");

        unchecked {

            _approve(_msgSender(), spender, currentAllowance - subtractedValue);

        }



        return true;

    }





    function _transfer(address _from, address _to, uint256 _amount) internal {

        require(_from != address(0), "BEP20: transfer from the zero address");

        require(_to != address(0), "BEP20: transfer to the zero address");



        uint256 senderBalance = _balances[_from];

        require(senderBalance >= _amount, "BEP20: transfer amount exceeds balance");





        bool takeFee = exchangePairs[_to] || exchangePairs[_from];

        if (_isExcludedFromFees[_from] || _isExcludedFromFees[_to]) {

            takeFee = false;

        }



        if (takeFee) {



            if (block.timestamp >= nextBurn && _balances[address(this)] > 0) {

                uint256 burnAmount = _balances[address(this)];

                _balances[address(this)] = 0;

                _balances[burnAddress] += burnAmount;

                emit Transfer(address(this), burnAddress, burnAmount);

                nextBurn = block.timestamp + 30 days;

            }



            uint256 fees = _amount * (burnFee + devFee + rewardFee) / denominator;

            _balances[_from] = senderBalance - _amount;

            _amount -= fees;

            distributeFees(_from, fees);

            _balances[_to] += _amount;

        } else {

            _balances[_from] = senderBalance - _amount;

            _balances[_to] += _amount;

        }

        emit Transfer(_from, _to, _amount);

    }



    function _approve(

        address owner,

        address spender,

        uint256 amount

    ) internal virtual {

        require(owner != address(0), "BEP20: approve from the zero address");

        require(spender != address(0), "BEP20: approve to the zero address");



        _allowances[owner][spender] = amount;

        emit Approval(owner, spender, amount);

    }



    function balanceOf(address account) external view override returns (uint256) {

        return _balances[account];

    }



    function distributeFees(address _from, uint256 _amount) internal {

        if (burnFee != 0) {

            uint256 burn = _amount * burnFee / getSumOfFees();

            _balances[address(this)] += burn;

            emit Transfer(_from, address(this), burn);

        }

        if (devFee != 0) {

            uint256 dev = _amount * devFee / getSumOfFees();

            _balances[devAddress] += dev;

            emit Transfer(_from, devAddress, dev);

        }

        if (rewardFee != 0) {

            uint256 reward = _amount * rewardFee / getSumOfFees();

            _balances[rewardAddress] += reward;

            emit Transfer(_from, rewardAddress, reward);

        }

    }





    function updateUniswapV2Router(address newAddress) external onlyOwner {

		require(newAddress != address(pancakeRouter), "MemeKing: The router already has that address");

		pancakeRouter = IPancakeRouter02(newAddress);

		address _pancakePair = IPancakeFactory(pancakeRouter.factory())

		.createPair(address(this), pancakeRouter.WETH());

        _setExchangePairs(_pancakePair, true);

	}



    function changeAllFees(uint256 _burnFee, uint256 _devFee, uint256 _rewardFee) external onlyOwner {

        _changeAllFees(_burnFee, _devFee, _rewardFee);

    }





    function _changeAllFees(uint256 _burnFee, uint256 _devFee, uint256 _rewardFee) internal {

        require(_burnFee + _devFee + _rewardFee <= maximumFee, "Maximum fee would be exceeded");

        require(_burnFee <= maxBurnFee, "Burn fee exceeds 2%");

        require(_devFee <= maxDevFee, "Dev fee exceeds 2%");

        require(_rewardFee <= maxRewardFee, "Reward fee exceeds 2%");

        burnFee = _burnFee;

        devFee = _devFee;

        rewardFee = _rewardFee;

    }



    function changeFeeAddresses(address _devAddress, address _rewardAddress) external onlyOwner {

        _changeFeeAddresses(_devAddress, _rewardAddress);

    }



    function _changeFeeAddresses(address _devAddress, address _rewardAddress) internal {

        devAddress = _devAddress;

        rewardAddress = _rewardAddress;

    }



    function changeFeeStatus(address account, bool excluded) external onlyOwner {

        _changeFeeStatus(account, excluded);

    }



    function _changeFeeStatus(address account, bool excluded) internal {

        _isExcludedFromFees[account] = excluded;

    }



    function setAutomatedMarketMakerPair(address pair, bool value) external onlyOwner {

		_setExchangePairs(pair, value);

	}



    function _setExchangePairs(address pair, bool value) internal {

		require(exchangePairs[pair] != value, "MemeKing: Automated market maker pair is already set to that value");

		exchangePairs[pair] = value;

	}



    function isExcludedFromFees(address account) external view returns(bool){

        return _isExcludedFromFees[account];

    }



    receive() external payable {

        revert("Sending BNB to the contract is not smart");

    }



}

pragma solidity ^0.8.0;

import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import './utils/Counters.sol';
import "./interfaces/IPancakeRouter02.sol";
import "./interfaces/IWBNB.sol";
import './tokens/LuckyToken.sol';

contract RevenueSharingPool is Ownable {

    using SafeERC20 for IERC20;
    using Counters for Counters.Counter;
    Counters.Counter private _roundId;


    IERC20 public luckyBusd;
    IERC20 public lucky;
    IERC20 public BUSD;
    IWBNB public wNative;
    IPancakeRouter02 public exchangeRouter;


    uint256 MAX_NUMBER;
    uint256 public START_ROUND_DATE;
    uint256 public MAX_DATE = 7;


    mapping(uint256 => mapping(uint256 => uint256)) public totalStake;
    mapping(uint256 => uint256) public totalLuckyRevenue;
    mapping(uint256 => mapping(uint256 => mapping(address => uint256))) stakeAmount; 

    mapping(address => bool) public whitelists;


    struct UserInfo {
        uint256 amount;
        uint256 rewardDept;
        uint256 pendingReward;
        uint256 lastUpdateRoundId;
    }

    mapping(address => UserInfo) public userInfo;


    struct PoolInfo {
	    uint256 winRate;
	    uint256 TPV;
	    uint256 buyBack;
	    uint256 TVL;
    }

    mapping(uint256 => PoolInfo) public poolInfo; 

    event DepositStake(address indexed account, uint256 amount, uint256 timestamp);
    event WithdrawStake(address indexed account, uint256 amount, uint256 timestamp);
    event ClaimReward(address indexed account, uint256 amount, uint256 timestamp);
    event DistributeLuckyRevenue(address from, address to, uint256 amounts);

    struct InputToken {
        address token;
        uint256 amount;
        address[] tokenToBUSDPath;
    }

    modifier isWhitelisted(address addr) {
        require(whitelists[addr], "Permission Denied");
        _;
    }

    constructor (
        address _lucky,
        address _luckyBusd,
        address owner_,
        IPancakeRouter02 _exchangeRouter,
        address _busd,
        address _wNative
    ) public {
        exchangeRouter = IPancakeRouter02(_exchangeRouter);
        luckyBusd = IERC20(_luckyBusd);
        lucky = IERC20(_lucky);
        wNative = IWBNB(_wNative);
        BUSD = IERC20(_busd);
        MAX_NUMBER = 0xffffffffffffffffffffffffffffffffffffffffffffffffffffffffffffffff;
        START_ROUND_DATE = block.timestamp;        
        transferOwnership(owner_);
    }


    receive() external payable {}




    function depositToken(uint256 amount) external {
        UserInfo storage user = userInfo[msg.sender];
        require(amount > 0, "Insufficient deposit amount!");
        luckyBusd.safeTransferFrom(msg.sender, address(this), amount);
        uint256 depositDate = getDepositDate();
        uint256 roundId = getCurrentRoundId();

        if (!isStakeUpToDate(roundId)) {
           updatePendingStake(); 
        }

        user.amount += amount;
        updateStake(roundId, depositDate, amount);
        emit DepositStake(msg.sender, amount, block.timestamp);
    }


    function withdrawToken() external {
        UserInfo storage user = userInfo[msg.sender];
        uint256 roundId = getCurrentRoundId();

        if (!isStakeUpToDate(roundId)) {
           updatePendingStake(); 
        }

        updatePendingReward();
        uint256 amount = user.amount;
        user.amount = 0;
        removeStake(roundId);
        luckyBusd.safeTransfer(msg.sender, amount);
        emit WithdrawStake(msg.sender, amount, block.timestamp);
    }


    function claimReward() external {
        UserInfo storage user = userInfo[msg.sender];
        uint256 roundId = getCurrentRoundId();

        if (user.amount > 0) {
            if (!isStakeUpToDate(roundId)) {
               updatePendingStake(); 
            }
            updatePendingReward();
        }

        uint256 claimableLuckyReward = user.pendingReward;
        require(claimableLuckyReward > 0, "Not enough claimable LUCKY reward!");
        user.rewardDept += claimableLuckyReward;
        user.pendingReward -= claimableLuckyReward;
        lucky.safeTransfer(msg.sender, claimableLuckyReward);
        emit ClaimReward(msg.sender, claimableLuckyReward, block.timestamp);
    }



    function updateRoundId() internal {
        _roundId.increment(); 
    }


    function updateMaxDate(uint256 newMaxDate) external onlyOwner {
        MAX_DATE = newMaxDate;
    }

    function addWhitelist(address addr) external onlyOwner {
        whitelists[addr] = true;
    }

    function removeWhitelist(address addr) external onlyOwner {
        whitelists[addr] = false;
    }

    function updatePoolInfo(uint256 winRate, uint256 TPV, uint256 buyBack, uint256 roundID) internal {
	    uint256 totalValueLock = luckyBusd.balanceOf(address(this));
	    PoolInfo storage _poolInfo = poolInfo[roundID];
	    _poolInfo.winRate = winRate;
	    _poolInfo.TPV = TPV;
            _poolInfo.buyBack = buyBack;
	    _poolInfo.TVL = totalValueLock;
    }

    function removeStake(uint256 roundId) internal {
        for (uint256 i = 1; i <= MAX_DATE; i++) {
            uint256 amount = stakeAmount[roundId][i][msg.sender];
            stakeAmount[roundId][i][msg.sender] -= amount;
            totalStake[roundId][i] -= amount;
        }
    }

    function updateStake(uint256 roundId, uint256 depositDate, uint256 amount) internal {
        for(uint256 i = depositDate; i <= MAX_DATE; i++) {
            stakeAmount[roundId][i][msg.sender] += amount;
            totalStake[roundId][i] += amount;
        }
    }


    function updatePendingStake() internal {
        UserInfo storage user = userInfo[msg.sender];
        uint256 lastUpdateRoundId = user.lastUpdateRoundId;
        uint256 currentRoundId = getCurrentRoundId();
        uint256 amount = user.amount;

        for(uint256 i = (lastUpdateRoundId + 1); i <= currentRoundId; i++) {
            for(uint256 j = 1; j <= MAX_DATE; j++) {
                stakeAmount[i][j][msg.sender] = amount;
            }
        }
        user.lastUpdateRoundId = currentRoundId;
    }

    function updateTotalStake(uint256 roundId) internal {
        uint256 _totalStake = luckyBusd.balanceOf(address(this));
        for(uint256 i = 1; i <= MAX_DATE; i++) {
            totalStake[roundId][i] = _totalStake;
        }
    }

    function updatePendingReward() internal {
        UserInfo storage user = userInfo[msg.sender];
        uint256 luckyReward = calculateTotalLuckyReward();
        uint256 luckyRewardDept = user.rewardDept;
        user.pendingReward = (luckyReward - luckyRewardDept);
    }

    function calculateLuckyReward(address account, uint256 roundId) internal view returns (uint256) {
        uint256 luckyReward;
        uint256 totalLuckyRevenuePerDay = getTotalLuckyRewardPerDay(roundId);
        if (totalLuckyRevenuePerDay == 0) {
            return 0;
        }
        for (uint256 i = 1; i <= MAX_DATE; i++) {
            uint256 amount = stakeAmount[roundId][i][account];
            if (amount == 0) continue;
            uint256 _totalStake = totalStake[roundId][i];
            uint256 userSharesPerDay = (amount * 1e18) / _totalStake;
            luckyReward += (totalLuckyRevenuePerDay * userSharesPerDay) / 1e18;
        }
        return luckyReward;
    }

    function calculateTotalLuckyReward() internal view returns (uint256) {
        uint256 totalLuckyReward = 0;
        uint256 roundId = getCurrentRoundId();
        for (uint256 i = 0; i < roundId; i++) { 
            totalLuckyReward += calculateLuckyReward(msg.sender, i);
        }
        return totalLuckyReward;
    }




    function getCurrentRoundId() public view returns (uint256) {
        return _roundId.current();
    }


    function getStakeAmount(uint256 roundId, uint256 day) public view returns (uint256) {
        return stakeAmount[roundId][day][msg.sender];
    }


    function getRoundPastTime() external view returns (uint256) {
        return (block.timestamp - START_ROUND_DATE);
    }


    function getDepositDate() internal view returns (uint256) {
        for (uint256 i = 1; i <= MAX_DATE; i++) { 
            if (block.timestamp >= START_ROUND_DATE && block.timestamp < START_ROUND_DATE + (i * 1 days)) { 
                return i;
            }
        }
    }


    function getTotalLuckyRewardPerDay(uint256 roundId) public view returns (uint256) {
        return (totalLuckyRevenue[roundId] / MAX_DATE);
    }


    function getLuckyBalance() external view returns (uint256) {
        return lucky.balanceOf(address(this));
    }


    function getLuckyBusdBalance() external view returns (uint256) {
        return luckyBusd.balanceOf(address(this));
    }


    function getPendingReward() external view returns (uint256) {
        UserInfo storage user = userInfo[msg.sender];
        if (user.amount == 0) {
            return user.pendingReward;
        }
        uint256 luckyReward = calculateTotalLuckyReward();
        uint256 luckyRewardDept = user.rewardDept;
        return (luckyReward - luckyRewardDept);
    }


    function getLuckyRewardPerRound(uint256 roundId) external view returns (uint256){
	    uint256 luckyReward = calculateLuckyReward(msg.sender, roundId);
	    return luckyReward;
    }


    function isStakeUpToDate(uint256 currentRoundId) internal view returns (bool) {
        return (userInfo[msg.sender].lastUpdateRoundId == currentRoundId);
    }




    function depositRevenue(
        InputToken[] calldata inputTokens,
        address[] calldata BUSDToOutputPath,
        uint256 minOutputAmount,
        uint256 winRate,
        uint256 TPV
    ) external payable isWhitelisted(msg.sender) {
        uint256 luckyRevenue;
        uint256 roundId = getCurrentRoundId();


        address[] memory _path = new address[](2);
            _path[0] = address(wNative);
            _path[1] = address(BUSD);


        if (msg.value > 0) {
            wNative.deposit{value: msg.value}();
            uint256 wNativeBalance = wNative.balanceOf(address(this));
            _swapExactNativeForBUSD(wNativeBalance, _path);
        }

        if (inputTokens.length > 0 ) {
            for (uint256 i; i < inputTokens.length; i++) {
                if (inputTokens[i].token == address(lucky)) { 
                    IERC20(lucky).safeTransferFrom(msg.sender, address(this), inputTokens[i].amount);
                    totalLuckyRevenue[roundId] += inputTokens[i].amount;
                    luckyRevenue += inputTokens[i].amount;
                } else if (inputTokens[i].token == address(BUSD)) { 
                    IERC20(BUSD).safeTransferFrom(msg.sender, address(this), inputTokens[i].amount);
                } else {  
                    _transferTokensToCave(inputTokens[i]);
                    _swapTokensForBUSD(inputTokens[i]);
                }
            }
        }

        uint256 BUSDBalance = BUSD.balanceOf(address(this));
        uint256 amountOut = _swapBUSDForToken( 
            BUSDBalance,
            BUSDToOutputPath
        );

        require(
            amountOut >= minOutputAmount,
            "Expect amountOut to be greater than minOutputAmount."
        );

        updatePoolInfo(winRate, TPV, BUSDBalance, roundId); 
        totalLuckyRevenue[roundId] += amountOut;
        luckyRevenue += amountOut;
        START_ROUND_DATE = block.timestamp;
        updateRoundId();
        uint256 currentRoundId = getCurrentRoundId();
        updateTotalStake(currentRoundId); 
        emit DistributeLuckyRevenue(msg.sender, address(this), luckyRevenue);
    }


    function _transferTokensToCave(InputToken calldata inputTokens) private {
            IERC20(inputTokens.token).safeTransferFrom(
                msg.sender,
                address(this),
                inputTokens.amount
            );
    }


    function _swapExactNativeForBUSD(uint256 amount, address[] memory path) private returns (uint256){
        if (amount == 0 || path[path.length - 1] == address(wNative)) {
            return amount;
        }
        wNative.approve(address(exchangeRouter), MAX_NUMBER);
        exchangeRouter.swapExactTokensForTokens(
            amount,
            0,
            path,
            address(this),
            block.timestamp + 60
        );
    }


    function _swapTokensForBUSD(InputToken calldata inputTokens) private {
        if (inputTokens.token != address(BUSD)) {
            IERC20(inputTokens.token).approve(address(exchangeRouter), MAX_NUMBER);
            exchangeRouter.swapExactTokensForTokens(
                inputTokens.amount,
                0, 
                inputTokens.tokenToBUSDPath,
                address(this),
                block.timestamp + 60
            );
        }
    }


    function _swapBUSDForToken(uint256 amount, address[] memory path)
        private
        returns (uint256)
    {
        if (amount == 0 || path[path.length - 1] == address(BUSD)) {
            return amount;
        }
        BUSD.approve(address(exchangeRouter), MAX_NUMBER);
        uint256[] memory amountOuts = exchangeRouter.swapExactTokensForTokens(
            amount,
            0,
            path,
            address(this),
            block.timestamp + 60
        );
        return amountOuts[amountOuts.length - 1];
    }
}

pragma solidity ^0.4.18;

import 'zeppelin-solidity/contracts/token/ERC20/StandardToken.sol';
import 'zeppelin-solidity/contracts/token/ERC20/BurnableToken.sol';
import 'zeppelin-solidity/contracts/ownership/Ownable.sol';
import 'zeppelin-solidity/contracts/math/SafeMath.sol';


contract Cloudbric is StandardToken, BurnableToken, Ownable {
    using SafeMath for uint256;

    string public constant symbol = "CLB";
    string public constant name = "Cloudbric";
    uint8 public constant decimals = 18;
    uint256 public constant INITIAL_SUPPLY = 1000000000 * (10 ** uint256(decimals));
    uint256 public constant TOKEN_SALE_ALLOWANCE = 540000000 * (10 ** uint256(decimals));
    uint256 public constant ADMIN_ALLOWANCE = INITIAL_SUPPLY - TOKEN_SALE_ALLOWANCE;


    address public adminAddr;


    address public tokenSaleAddr;


    bool public transferEnabled = false;


    mapping(address => uint256) private lockedAccounts;




    modifier onlyWhenTransferAllowed() {
        require(transferEnabled == true
            || msg.sender == adminAddr
            || msg.sender == tokenSaleAddr);
        _;
    }


    modifier onlyWhenTokenSaleAddrNotSet() {
        require(tokenSaleAddr == address(0x0));
        _;
    }


    modifier onlyValidDestination(address to) {
        require(to != address(0x0)
            && to != address(this)
            && to != owner
            && to != adminAddr
            && to != tokenSaleAddr);
        _;
    }

    modifier onlyAllowedAmount(address from, uint256 amount) {
        require(balances[from].sub(amount) >= lockedAccounts[from]);
        _;
    }

    function Cloudbric(address _adminAddr) public {
        totalSupply_ = INITIAL_SUPPLY;

        balances[msg.sender] = totalSupply_;
        Transfer(address(0x0), msg.sender, totalSupply_);

        adminAddr = _adminAddr;
        approve(adminAddr, ADMIN_ALLOWANCE);
    }


    function setTokenSaleAmount(address _tokenSaleAddr, uint256 amountForSale)
        external
        onlyOwner
        onlyWhenTokenSaleAddrNotSet
    {
        require(!transferEnabled);

        uint256 amount = (amountForSale == 0) ? TOKEN_SALE_ALLOWANCE : amountForSale;
        require(amount <= TOKEN_SALE_ALLOWANCE);

        approve(_tokenSaleAddr, amount);
        tokenSaleAddr = _tokenSaleAddr;
    }


    function enableTransfer() external onlyOwner {
        transferEnabled = true;
        approve(tokenSaleAddr, 0);
    }


    function disableTransfer() external onlyOwner {
        transferEnabled = false;
    }


    function transfer(address to, uint256 value)
        public
        onlyWhenTransferAllowed
        onlyValidDestination(to)
        onlyAllowedAmount(msg.sender, value)
        returns (bool)
    {
        return super.transfer(to, value);
    }


    function transferFrom(address from, address to, uint256 value)
        public
        onlyWhenTransferAllowed
        onlyValidDestination(to)
        onlyAllowedAmount(from, value)
        returns (bool)
    {
        return super.transferFrom(from, to, value);
    }


    function burn(uint256 value) public onlyOwner {
        require(transferEnabled);
        super.burn(value);
    }


    function lockAccount(address addr, uint256 amount)
        external
        onlyOwner
        onlyValidDestination(addr)
    {
        require(amount > 0);
        lockedAccounts[addr] = amount;
    }



    function unlockAccount(address addr)
        external
        onlyOwner
        onlyValidDestination(addr)
    {
        lockedAccounts[addr] = 0;
    }
}

pragma solidity ^0.4.18;

import "./Cloudbric.sol";
import "zeppelin-solidity/contracts/math/SafeMath.sol";
import "zeppelin-solidity/contracts/lifecycle/Pausable.sol";

contract CloudbricSale is Pausable {
    using SafeMath for uint256;


    uint256 public startTime;

    uint256 public endTime;

    address private fundAddr;

    Cloudbric public token;

    uint256 public totalWeiRaised;

    uint256 public constant BASE_HARD_CAP_PER_ROUND = 20000 * 1 ether;

    uint256 public constant UINT256_MAX = ~uint256(0);

    uint256 public constant BASE_CLB_TO_ETH_RATE = 10000;

    uint256 public constant BASE_MIN_CONTRIBUTION = 0.1 * 1 ether;

    mapping(address => bool) public whitelist;

    mapping(address => mapping(uint8 => uint256)) public contPerRound;


    enum Stages {
        SetUp,
        Started,
        Ended
    }

    Stages public stage;


    enum SaleRounds {
        EarlyInvestment,
        PreSale1,
        PreSale2,
        CrowdSale
    }

    SaleRounds public round;


    struct RoundInfo {
        uint256 minContribution;
        uint256 maxContribution;
        uint256 hardCap;
        uint256 rate;
        uint256 weiRaised;
    }



    mapping(uint8 => RoundInfo) public roundInfos;

    struct AllocationInfo {
        bool isAllowed;
        uint256 allowedAmount;
    }


    mapping(address => AllocationInfo) private allocationList;


    event SaleStarted(uint256 startTime, uint256 endTime, SaleRounds round);


    event SaleEnded(uint256 endTime, uint256 totalWeiRaised, SaleRounds round);


    event TokenPurchase(address indexed purchaser, uint256 value, uint256 amount);


    modifier atStage(Stages expectedStage) {
        require(stage == expectedStage);
        _;
    }


    modifier atRound(SaleRounds expectedRound) {
        require(round == expectedRound);
        _;
    }


    modifier onlyValidPurchase() {
        require(round <= SaleRounds.CrowdSale);
        require(now >= startTime && now <= endTime);

        uint256 contributionInWei = msg.value;
        address purchaser = msg.sender;

        require(whitelist[purchaser]);
        require(purchaser != address(0));
        require(contributionInWei >= roundInfos[uint8(round)].minContribution);
        require(
            contPerRound[purchaser][uint8(round)].add(contributionInWei)
            <= roundInfos[uint8(round)].maxContribution
        );
        require(
            roundInfos[uint8(round)].weiRaised.add(contributionInWei)
            <= roundInfos[uint8(round)].hardCap
        );
        _;
    }


    function CloudbricSale(
        address fundAddress,
        address tokenAddress
    )
        public
    {
        require(fundAddress != address(0));
        require(tokenAddress != address(0));

        token = Cloudbric(tokenAddress);
        fundAddr = fundAddress;
        stage = Stages.Ended;
        round = SaleRounds.EarlyInvestment;
        uint8 roundIndex = uint8(round);

        roundInfos[roundIndex].minContribution = BASE_MIN_CONTRIBUTION;
        roundInfos[roundIndex].maxContribution = UINT256_MAX;
        roundInfos[roundIndex].hardCap = BASE_HARD_CAP_PER_ROUND;
        roundInfos[roundIndex].weiRaised = 0;
        roundInfos[roundIndex].rate = BASE_CLB_TO_ETH_RATE;
    }


    function () public payable {
        buy();
    }


    function withdraw() external onlyOwner {
        fundAddr.transfer(this.balance);
    }


    function addManyToWhitelist(address[] users) external onlyOwner {
        for (uint32 i = 0; i < users.length; i++) {
            addToWhitelist(users[i]);
        }
    }


    function addToWhitelist(address user) public onlyOwner {
        whitelist[user] = true;
    }


    function removeManyFromWhitelist(address[] users) external onlyOwner {
        for (uint32 i = 0; i < users.length; i++) {
            removeFromWhitelist(users[i]);
        }
    }


    function removeFromWhitelist(address user) public onlyOwner {
        whitelist[user] = false;
    }


    function setMinContributionForRound(
        SaleRounds _round,
        uint256 _minContribution
    )
        public
        onlyOwner
        atStage(Stages.SetUp)
    {
        require(round <= _round);
        roundInfos[uint8(_round)].minContribution =
            (_minContribution == 0) ? BASE_MIN_CONTRIBUTION : _minContribution;
    }


    function setMaxContributionForRound(
        SaleRounds _round,
        uint256 _maxContribution
    )
        public
        onlyOwner
        atStage(Stages.SetUp)
    {
        require(round <= _round);
        roundInfos[uint8(_round)].maxContribution =
            (_maxContribution == 0) ? UINT256_MAX : _maxContribution;
    }


    function setHardCapForRound(
        SaleRounds _round,
        uint256 _hardCap
    )
        public
        onlyOwner
        atStage(Stages.SetUp)
    {
        require(round <= _round);
        roundInfos[uint8(_round)].hardCap =
            (_hardCap == 0) ? BASE_HARD_CAP_PER_ROUND : _hardCap;
    }


    function setRateForRound(
        SaleRounds _round,
        uint256 _rate
    )
        public
        onlyOwner
        atStage(Stages.SetUp)
    {
        require(round <= _round);
        roundInfos[uint8(_round)].rate =
            (_rate == 0) ? BASE_CLB_TO_ETH_RATE : _rate;
    }


    function setUpSale(
        SaleRounds _round,
        uint256 _minContribution,
        uint256 _maxContribution,
        uint256 _hardCap,
        uint256 _rate
    )
        external
        onlyOwner
        atStage(Stages.Ended)
    {
        require(round <= _round);
        stage = Stages.SetUp;
        round = _round;
        setMinContributionForRound(_round, _minContribution);
        setMaxContributionForRound(_round, _maxContribution);
        setHardCapForRound(_round, _hardCap);
        setRateForRound(_round, _rate);
    }


    function startSale(uint256 durationInSeconds)
        external
        onlyOwner
        atStage(Stages.SetUp)
    {
        require(roundInfos[uint8(round)].minContribution > 0
            && roundInfos[uint8(round)].hardCap > 0);
        stage = Stages.Started;
        startTime = now;
        endTime = startTime.add(durationInSeconds);
        SaleStarted(startTime, endTime, round);
    }


    function endSale() external onlyOwner atStage(Stages.Started) {
        endTime = now;
        stage = Stages.Ended;

        SaleEnded(endTime, totalWeiRaised, round);
    }

    function buy()
        public
        payable
        whenNotPaused
        atStage(Stages.Started)
        onlyValidPurchase()
        returns (bool)
    {
        address purchaser = msg.sender;
        uint256 contributionInWei = msg.value;
        uint256 tokenAmount = contributionInWei.mul(roundInfos[uint8(round)].rate);

        if (!token.transferFrom(token.owner(), purchaser, tokenAmount)) {
            revert();
        }

        totalWeiRaised = totalWeiRaised.add(contributionInWei);
        roundInfos[uint8(round)].weiRaised =
            roundInfos[uint8(round)].weiRaised.add(contributionInWei);

        contPerRound[purchaser][uint8(round)] =
            contPerRound[purchaser][uint8(round)].add(contributionInWei);


        fundAddr.transfer(contributionInWei);
        TokenPurchase(msg.sender, contributionInWei, tokenAmount);

        return true;
    }


    function addToAllocationList(address user, uint256 amount)
        public
        onlyOwner
        atRound(SaleRounds.EarlyInvestment)
    {
        allocationList[user].isAllowed = true;
        allocationList[user].allowedAmount = amount;
    }


    function addManyToAllocationList(address[] users, uint256[] amounts)
        external
        onlyOwner
        atRound(SaleRounds.EarlyInvestment)
    {
        require(users.length == amounts.length);

        for (uint32 i = 0; i < users.length; i++) {
            addToAllocationList(users[i], amounts[i]);
        }
    }


    function removeFromAllocationList(address user)
        public
        onlyOwner
        atRound(SaleRounds.EarlyInvestment)
    {
        allocationList[user].isAllowed = false;
    }


    function removeManyFromAllocationList(address[] users)
        external
        onlyOwner
        atRound(SaleRounds.EarlyInvestment)
    {
        for (uint32 i = 0; i < users.length; i++) {
            removeFromAllocationList(users[i]);
        }
    }



    function allocateTokens(address to, uint256 tokenAmount)
        public
        onlyOwner
        atRound(SaleRounds.EarlyInvestment)
        returns (bool)
    {
        require(allocationList[to].isAllowed
            && tokenAmount <= allocationList[to].allowedAmount);

        if (!token.transferFrom(token.owner(), to, tokenAmount)) {
            revert();
        }
        return true;
    }


    function allocateTokensToMany(address[] toList, uint256[] tokenAmountList)
        external
        onlyOwner
        atRound(SaleRounds.EarlyInvestment)
        returns (bool)
    {
        require(toList.length == tokenAmountList.length);

        for (uint32 i = 0; i < toList.length; i++) {
            allocateTokens(toList[i], tokenAmountList[i]);
        }
        return true;
    }
}

